INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2s0068wrk1q4l0agh8', 'cmrq0ao2s0063wrk1g755l3w4', 4, 'LIST', 'При выборе журнала автору полезно смотреть', 'Jurnal tanlashda muallif uchun quyidagilarni ko‘rish foydali', 'When choosing a journal, it is useful for an author to check', NULL, NULL, NULL, '{"есть ли ISSN;","указан ли издатель;","существует ли архив выпусков;","есть ли peer review policy;","где журнал индексируется;","открыта ли информация о редакции и правилах подачи."}', '{"ISSN bormi;","nashriyot ko‘rsatilganmi;","sonlar arxivi bormi;","peer review policy bormi;","jurnal qayerda indekslanadi;","tahririyat va topshirish qoidalari haqidagi ma’lumot ochiqmi."}', '{"whether it has an ISSN;","whether the publisher is identified;","whether an archive of issues exists;","whether there is a peer review policy;","where the journal is indexed;","whether information about the editorial board and submission rules is openly available."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2s0069wrk1jmij417j', 'cmrq0ao2s0063wrk1g755l3w4', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Научный журнал — это регулярное академическое издание, а не просто площадка, где можно разместить текст.', 'Ilmiy jurnal — bu shunchaki matn joylashtiriladigan joy emas, balki muntazam akademik nashrdir.', 'A scientific journal is a regular academic publication, not just a place where one can post a text.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006bwrk166rg8a40', 'cmrq0ao2z006awrk106wal4qw', 0, 'PARAGRAPH', 'В чём разница', 'Farqi nimada', 'What is the difference', 'Тезисы обычно готовят для конференций, сборников материалов или предварительного представления исследования. Их задача — кратко показать, о чём работа, в чём её идея и какие получены основные результаты.', 'Tezislar odatda konferensiyalar, materiallar to‘plamlari yoki tadqiqotni dastlabki taqdim etish uchun tayyorlanadi. Ularning vazifasi ish nima haqida ekanini, g‘oyasi nimada ekanini va qanday asosiy natijalar olinganini qisqacha ko‘rsatishdir.', 'Theses or abstract texts are usually prepared for conferences, proceedings, or preliminary presentation of research. Their task is to briefly show what the work is about, what its main idea is, and what key results were obtained.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006cwrk179c3l3yi', 'cmrq0ao2z006awrk106wal4qw', 1, 'PARAGRAPH', NULL, NULL, NULL, 'Научная статья решает другую задачу. Она не просто анонсирует исследование, а подробно показывает, какую проблему изучал автор, на какой научный контекст он опирался, какие методы использовал, какие результаты получил и как эти результаты интерпретируются.', 'Ilmiy maqola esa boshqa vazifani bajaradi. U tadqiqotni shunchaki e’lon qilmaydi, balki muallif qanday muammoni o‘rganganini, qaysi ilmiy kontekstga tayanganini, qanday metodlardan foydalanganini, qanday natijalar olganini va bu natijalar qanday talqin qilinishini batafsil ko‘rsatadi.', 'A scientific article serves a different purpose. It does not merely announce the research, but shows in detail what problem the author studied, what scholarly context it relied on, what methods were used, what results were obtained, and how those results are interpreted.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006dwrk1y94msrva', 'cmrq0ao2z006awrk106wal4qw', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Если говорить совсем просто, тезисы отвечают на вопрос «о чём исследование?», а статья — на вопрос «как именно оно проведено и почему выводы заслуживают доверия?»', 'Juda sodda aytganda, tezislar «tadqiqot nima haqida?» degan savolga javob beradi, maqola esa «u aynan qanday o‘tkazildi va nima uchun xulosalarga ishonish mumkin?» degan savolga javob beradi.', 'Put very simply, theses answer the question “What is the research about?”, whereas an article answers “How exactly was it conducted and why are the conclusions trustworthy?”', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006ewrk1i7a70s8u', 'cmrq0ao2z006awrk106wal4qw', 3, 'LIST', 'Что обычно содержат тезисы', 'Tezislar odatda nimani o‘z ichiga oladi', 'What theses usually contain', NULL, NULL, NULL, '{"тему исследования;","цель работы;","краткое описание подхода;","основные результаты;","короткий вывод."}', '{"tadqiqot mavzusini;","ishning maqsadini;","yondashuvning qisqacha tavsifini;","asosiy natijalarni;","qisqa xulosani."}', '{"the research topic;","the aim of the work;","a brief description of the approach;","the main results;","a short conclusion."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006fwrk12sm5jmb8', 'cmrq0ao2z006awrk106wal4qw', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Они компактны, быстро читаются и не требуют полного раскрытия всех деталей.', 'Ular ixcham bo‘ladi, tez o‘qiladi va barcha tafsilotlarni to‘liq ochishni talab qilmaydi.', 'They are compact, quick to read, and do not require full disclosure of all details.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006gwrk1luoaow53', 'cmrq0ao2z006awrk106wal4qw', 5, 'LIST', 'Что обычно содержит научная статья', 'Ilmiy maqola odatda nimani o‘z ichiga oladi', 'What a scientific article usually contains', NULL, NULL, NULL, '{заголовок;,аннотацию;,введение;,методы;,результаты;,обсуждение;,выводы;,"список литературы."}', '{sarlavha;,annotatsiya;,kirish;,metodlar;,natijalar;,muhokama;,xulosalar;,"adabiyotlar ro‘yxatini."}', '{title;,abstract;,introduction;,methods;,results;,discussion;,conclusions;,references.}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006hwrk1nwm8qu34', 'cmrq0ao2z006awrk106wal4qw', 6, 'PARAGRAPH', NULL, NULL, NULL, 'Именно поэтому статья считается основным форматом научного сообщения, а тезисы — сокращённым.', 'Shuning uchun maqola ilmiy xabarning asosiy formati, tezislar esa qisqartirilgan shakli hisoblanadi.', 'That is why an article is considered the main format of scholarly communication, while theses are a shortened form.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006iwrk1n05t6k10', 'cmrq0ao2z006awrk106wal4qw', 7, 'PARAGRAPH', 'Почему это важно автору', 'Bu muallif uchun nega muhim', 'Why this matters for an author', 'Авторы часто считают, что если тезисы опубликованы, то это уже эквивалент статьи. На практике это не так. Тезисы могут учитываться как публикационная активность в определённом контексте, но обычно не приравниваются к полноценной журнальной статье.', 'Mualliflar ko‘pincha tezislar chop etilgan bo‘lsa, bu allaqachon maqolaga teng deb hisoblaydilar. Amalda unday emas. Tezislar ma’lum kontekstda nashr faolligi sifatida hisobga olinishi mumkin, lekin odatda to‘laqonli jurnal maqolasiga tenglashtirilmaydi.', 'Authors often believe that if theses are published, this is already equivalent to an article. In practice, this is not so. Theses may count as publication activity in a certain context, but they are usually not treated as equivalent to a full journal article.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2z006jwrk1m8uk7is8', 'cmrq0ao2z006awrk106wal4qw', 8, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Тезисы — это краткое представление исследования. Научная статья — это полное и обоснованное изложение научной работы.', 'Tezislar — tadqiqotning qisqacha taqdimotidir. Ilmiy maqola esa ilmiy ishning to‘liq va asoslangan bayonidir.', 'Theses are a brief presentation of research. A scientific article is a complete and reasoned exposition of scholarly work.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006lwrk15zefgdsa', 'cmrq0ao34006kwrk1c4xy1ot8', 0, 'PARAGRAPH', 'Что означает ISSN', 'ISSN nimani anglatadi', 'What ISSN means', 'ISSN расшифровывается как International Standard Serial Number. Это специальный 8-значный код, который присваивается журналу или другому продолжающемуся изданию.', 'ISSN — International Standard Serial Number degani. Bu jurnal yoki boshqa davomli nashrga beriladigan maxsus 8 xonali koddir.', 'ISSN stands for International Standard Serial Number. It is a special 8-digit code assigned to a journal or another continuing publication.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006mwrk1hfrnpbtd', 'cmrq0ao34006kwrk1c4xy1ot8', 1, 'PARAGRAPH', 'Пример записи', 'Yozuv namunasi', 'Example record', 'ISSN 1234-5678', 'ISSN 1234-5678', 'ISSN 1234-5678', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006nwrk1092zralx', 'cmrq0ao34006kwrk1c4xy1ot8', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Этот номер нужен не для красоты и не для рекламы. Его основная функция — точно отличать одно издание от другого, особенно если названия похожи или менялись со временем.', 'Bu raqam bezak yoki reklama uchun emas. Uning asosiy vazifasi — ayniqsa nomlari o‘xshash yoki vaqt o‘tishi bilan o‘zgargan bo‘lsa, bir nashrni boshqasidan aniq ajratishdir.', 'This number is not for appearance or advertising. Its main function is to accurately distinguish one publication from another, especially when titles are similar or have changed over time.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006owrk1qmeko3cp', 'cmrq0ao34006kwrk1c4xy1ot8', 3, 'LIST', 'Для чего нужен ISSN', 'ISSN nima uchun kerak', 'Why ISSN is needed', NULL, NULL, NULL, '{"правильно идентифицировать журнал;","связывать его с базами данных и каталогами;","избегать путаницы между похожими названиями;","вести библиотечный и издательский учёт."}', '{"jurnalni to‘g‘ri identifikatsiya qilish;","uni ma’lumotlar bazalari va kataloglar bilan bog‘lash;","o‘xshash nomlar orasidagi chalkashlikning oldini olish;","kutubxona va nashriyot hisobini yuritish."}', '{"to correctly identify a journal;","to connect it with databases and catalogues;","to avoid confusion between similar titles;","to support library and publishing records."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006pwrk16ya7htn8', 'cmrq0ao34006kwrk1c4xy1ot8', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Для сайта о журналах ISSN особенно полезен как технический ориентир: по нему удобнее сверять источник в Scopus, Crossref, каталогах и других системах.', 'Jurnallar haqidagi sayt uchun ISSN texnik yo‘naltiruvchi sifatida ayniqsa foydalidir: uning yordamida manbani Scopus, Crossref, kataloglar va boshqa tizimlarda solishtirish osonroq bo‘ladi.', 'For a website about journals, ISSN is especially useful as a technical reference point: it makes it easier to verify a source in Scopus, Crossref, catalogues, and other systems.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006qwrk1l2zjgto3', 'cmrq0ao34006kwrk1c4xy1ot8', 5, 'LIST', 'Что ISSN не показывает', 'ISSN nimani ko‘rsatmaydi', 'What ISSN does not show', NULL, NULL, NULL, '{"не подтверждает, что журнал индексируется в Scopus;","не гарантирует качество журнала;","не делает издание автоматически научным или добросовестным;","не показывает страну или репутацию издателя."}', '{"jurnal Scopus’da indekslanishini tasdiqlamaydi;","jurnal sifatini kafolatlamaydi;","nashrni avtomatik ravishda ilmiy yoki halol qilmaydi;","nashriyotning mamlakati yoki obro‘sini ko‘rsatmaydi."}', '{"it does not confirm that the journal is indexed in Scopus;","it does not guarantee journal quality;","it does not make a publication automatically scholarly or trustworthy;","it does not show the publisher’s country or reputation."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006rwrk14e8pc8k1', 'cmrq0ao34006kwrk1c4xy1ot8', 6, 'PARAGRAPH', NULL, NULL, NULL, 'Иными словами, ISSN — это идентификатор, а не знак качества.', 'Boshqacha aytganda, ISSN — bu sifat belgisi emas, identifikatordir.', 'In other words, ISSN is an identifier, not a mark of quality.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006swrk11ta56e0s', 'cmrq0ao34006kwrk1c4xy1ot8', 7, 'PARAGRAPH', 'Print ISSN и eISSN', 'Print ISSN va eISSN', 'Print ISSN and eISSN', 'У одного журнала может быть два номера: print ISSN — для печатной версии; eISSN — для электронной версии. Это нормальная практика. Если журнал выходит и в печатной, и в онлайн-форме, у каждой версии может быть свой отдельный идентификатор.', 'Bitta jurnalda ikki raqam bo‘lishi mumkin: print ISSN — bosma versiya uchun; eISSN — elektron versiya uchun. Bu normal amaliyot. Agar jurnal bosma hamda onlayn shaklda chiqsa, har bir versiyaning alohida identifikatori bo‘lishi mumkin.', 'A single journal may have two numbers: print ISSN for the print version and eISSN for the electronic version. This is normal practice. If a journal appears both in print and online, each version may have its own separate identifier.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao34006twrk1tnvtzz6l', 'cmrq0ao34006kwrk1c4xy1ot8', 8, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'ISSN нужен для точного распознавания журнала. Это полезный и важный номер, но сам по себе он не говорит ни о качестве журнала, ни о его индексации.', 'ISSN jurnalni aniq tanib olish uchun kerak. Bu foydali va muhim raqam, lekin uning o‘zi jurnal sifati yoki indeksatsiyasi haqida gapirmaydi.', 'ISSN is needed for the precise identification of a journal. It is a useful and important number, but by itself it says nothing about journal quality or indexing.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao39006vwrk1o230jzsq', 'cmrq0ao39006uwrk119hwt0ue', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Определение страны журнала кажется простой задачей, но на практике именно здесь авторы часто ошибаются. Международное название, английский сайт или привычный домен ещё не означают, что журнал действительно относится к той стране, которую предполагает автор.', 'Jurnal mamlakatini aniqlash oddiy vazifa bo‘lib tuyuladi, lekin amalda mualliflar aynan shu yerda ko‘p xato qiladilar. Xalqaro nom, inglizcha sayt yoki odatiy domen jurnal muallif taxmin qilgan mamlakatga tegishli ekanini anglatmaydi.', 'Determining a journal’s country seems simple, but in practice authors often make mistakes here. An international-sounding title, an English-language website, or a familiar domain does not yet mean that the journal actually belongs to the country assumed by the author.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao39006wwrk1vhynyied', 'cmrq0ao39006uwrk119hwt0ue', 1, 'LIST', 'Почему здесь так много ошибок', 'Nega bu yerda xatolar ko‘p', 'Why there are so many mistakes here', NULL, NULL, NULL, '{"сайт на английском языке;","название звучит «международно»;","домен .com или .org;","в редакции есть иностранные специалисты;","журнал использует латиницу и западный стиль оформления."}', '{"sayt ingliz tilida bo‘lishi;","nomi «xalqaro» eshitilishi;","domen .com yoki .org bo‘lishi;","tahririyatda xorijiy mutaxassislar bo‘lishi;","jurnal lotin yozuvi va g‘arbona uslubdan foydalanishi."}', '{"the website is in English;","the title sounds “international”;","the domain is .com or .org;","there are foreign specialists on the editorial board;","the journal uses Latin script and a Western style of presentation."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao39006xwrk1yhd2lxaf', 'cmrq0ao39006uwrk119hwt0ue', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Но всё это не даёт надёжного ответа.', 'Ammo bularning hech biri ishonchli javob bermaydi.', 'But none of this gives a reliable answer.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyi001ewrk11ima1e8d', 'cmrq0anyh001dwrk1t9li47qr', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'ORCID расшифровывается как Open Researcher and Contributor ID. Это международная система, которая присваивает исследователю уникальный цифровой код и помогает избежать путаницы в авторстве.', 'ORCID — Open Researcher and Contributor ID degani. Bu tadqiqotchiga noyob raqamli kod beradigan xalqaro tizim bo‘lib, mualliflikdagi chalkashliklarning oldini olishga yordam beradi.', 'ORCID stands for Open Researcher and Contributor ID. It is an international system that assigns a researcher a unique digital code and helps avoid confusion in authorship.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyi001fwrk1d7aybcqz', 'cmrq0anyh001dwrk1t9li47qr', 1, 'LIST', 'Такой идентификатор особенно полезен, если', 'Bunday identifikator ayniqsa quyidagi holatlarda foydali', 'Such an identifier is especially useful if', NULL, NULL, NULL, '{"у автора распространённая фамилия;","имя пишется по-разному на разных языках;","автор меняет место работы;","нужно объединить публикации из разных платформ в одну научную историю."}', '{"muallifning familiyasi juda keng tarqalgan bo‘lsa;","ismi turli tillarda turlicha yozilsa;","muallif ish joyini o‘zgartirsa;","turli platformalardagi nashrlarni bitta ilmiy tarixga birlashtirish kerak bo‘lsa."}', '{"the author has a common surname;","the name is written differently in different languages;","the author changes institution;","publications from different platforms need to be combined into one research history."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyi001gwrk1q44eqqq2', 'cmrq0anyh001dwrk1t9li47qr', 2, 'PARAGRAPH', 'Пример ORCID', 'ORCID misoli', 'Example of ORCID', 'https://orcid.org/0000-0002-1825-0097', 'https://orcid.org/0000-0002-1825-0097', 'https://orcid.org/0000-0002-1825-0097', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyi001hwrk1g59awgc8', 'cmrq0anyh001dwrk1t9li47qr', 3, 'LIST', 'ORCID можно указывать', 'ORCID quyidagi joylarda ko‘rsatiladi', 'ORCID can be used', NULL, NULL, NULL, '{"при подаче статьи в журнал;","в профиле автора;","в заявках на гранты;","в университетских и издательских системах;","в метаданных публикации."}', '{"jurnalga maqola topshirishda;","muallif profilida;","grant arizalarida;","universitet va nashriyot tizimlarida;","nashr metama’lumotlarida."}', '{"when submitting an article to a journal;","in the author profile;","in grant applications;","in university and publisher systems;","in publication metadata."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyi001iwrk14n92464i', 'cmrq0anyh001dwrk1t9li47qr', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Важно понимать: ORCID не заменяет Scopus Author ID или Google Scholar Profile. Это другая система. Но именно ORCID часто используется как универсальный идентификатор, который признают многие издатели и научные платформы.', 'Muhimi shundaki, ORCID Scopus Author ID yoki Google Scholar Profile o‘rnini bosmaydi. Bu boshqa tizim. Lekin aynan ORCID ko‘plab nashriyotlar va ilmiy platformalar tan oladigan universal identifikator sifatida tez-tez qo‘llanadi.', 'It is important to understand that ORCID does not replace Scopus Author ID or Google Scholar Profile. It is a different system. However, ORCID is often used as a universal identifier recognized by many publishers and research platforms.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyi001jwrk1fye1t4qm', 'cmrq0anyh001dwrk1t9li47qr', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'ORCID — это не показатель качества и не метрика. Это инструмент точной идентификации автора.', 'ORCID sifat ko‘rsatkichi ham, metrika ham emas. Bu muallifni aniq identifikatsiya qilish vositasidir.', 'ORCID is not a quality indicator or a metric. It is a tool for accurate author identification.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyw001lwrk1iad4hn6l', 'cmrq0anyv001kwrk1njd2wo0y', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'DOI расшифровывается как Digital Object Identifier. Это устойчивый идентификатор объекта, который остаётся с ним даже в том случае, если сайт издателя или ссылка на публикацию меняются.', 'DOI — Digital Object Identifier degani. Bu obyektning barqaror identifikatori bo‘lib, nashriyot sayti yoki havola o‘zgarsa ham u saqlanib qoladi.', 'DOI stands for Digital Object Identifier. It is a persistent identifier of an object that remains with it even if the publisher’s website or publication link changes.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyw001mwrk1nrujtmvi', 'cmrq0anyv001kwrk1njd2wo0y', 1, 'PARAGRAPH', 'Пример DOI', 'DOI misoli', 'Example DOI', '10.1000/182', '10.1000/182', '10.1000/182', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyw001nwrk1bxxsp9ky', 'cmrq0anyv001kwrk1njd2wo0y', 2, 'PARAGRAPH', 'Как ссылка DOI выглядит так', 'DOI havolasi quyidagicha ko‘rinadi', 'A DOI link looks like this', 'https://doi.org/10.1000/182', 'https://doi.org/10.1000/182', 'https://doi.org/10.1000/182', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyw001owrk1ed6so44e', 'cmrq0anyv001kwrk1njd2wo0y', 3, 'LIST', 'Главные преимущества DOI', 'DOI ning asosiy afzalliklari', 'Main advantages of DOI', NULL, NULL, NULL, '{"он уникален;","он постоянен;","он облегчает поиск публикации;","он используется в научных ссылках и библиографических системах."}', '{"u noyobdir;","u doimiydir;","u nashrni topishni osonlashtiradi;","u ilmiy havolalar va bibliografik tizimlarda qo‘llanadi."}', '{"it is unique;","it is persistent;","it facilitates discovery of the publication;","it is used in scholarly references and bibliographic systems."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyw001pwrk18mhgxfdh', 'cmrq0anyv001kwrk1njd2wo0y', 4, 'PARAGRAPH', NULL, NULL, NULL, 'DOI особенно важен для корректного цитирования. Даже если издатель перенёс статью на другой адрес, DOI должен продолжать вести к актуальной версии записи.', 'DOI to‘g‘ri iqtibos keltirish uchun ayniqsa muhim. Nashriyot maqolani boshqa manzilga ko‘chirgan taqdirda ham, DOI dolzarb yozuvga olib borishi kerak.', 'DOI is especially important for correct citation. Even if the publisher moves the article to another address, the DOI should continue to lead to the current version of the record.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyw001qwrk18jo4qazh', 'cmrq0anyv001kwrk1njd2wo0y', 5, 'PARAGRAPH', NULL, NULL, NULL, 'Но есть важное уточнение: DOI не означает индексацию. Если у статьи есть DOI, это не значит, что она автоматически включена в Scopus, Web of Science или другую международную базу. DOI — это идентификатор объекта, а не подтверждение статуса журнала.', 'Ammo muhim aniqlik bor: DOI indeksatsiyani anglatmaydi. Maqolada DOI borligi uning avtomatik ravishda Scopus, Web of Science yoki boshqa xalqaro bazaga kiritilganini anglatmaydi. DOI — bu obyekt identifikatori, jurnal maqomining tasdig‘i emas.', 'However, there is an important clarification: DOI does not mean indexing. If an article has a DOI, that does not mean it is automatically included in Scopus, Web of Science, or another international database. DOI is an object identifier, not confirmation of journal status.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anyw001rwrk10airgqxb', 'cmrq0anyv001kwrk1njd2wo0y', 6, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'DOI — это постоянный адрес научного объекта, но не знак качества и не гарантия индексации.', 'DOI — ilmiy obyektning doimiy manzili, ammo sifat belgisi ham, indeksatsiya kafolati ham emas.', 'DOI is a persistent address of a scholarly object, but not a quality mark or a guarantee of indexing.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anz3001twrk1nxrxacry', 'cmrq0anz2001swrk1ijyhvkzj', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Scopus — это одна из крупнейших научных баз данных. Она используется для поиска публикаций, проверки журналов, анализа цитируемости и оценки научной активности авторов и организаций.', 'Scopus — eng yirik ilmiy ma’lumotlar bazalaridan biridir. U nashrlarni qidirish, jurnallarni tekshirish, iqtiboslilikni tahlil qilish va mualliflar hamda tashkilotlarning ilmiy faolligini baholash uchun ishlatiladi.', 'Scopus is one of the largest scholarly databases. It is used for finding publications, checking journals, analyzing citations, and evaluating the research activity of authors and institutions.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anz3001uwrk1tg0u7qka', 'cmrq0anz2001swrk1ijyhvkzj', 1, 'LIST', 'Scopus включает несколько уровней данных', 'Scopus bir necha darajadagi ma’lumotlarni o‘z ichiga oladi', 'Scopus includes several levels of data', NULL, NULL, NULL, '{"источники — журналы, proceedings, book series;","документы — статьи, обзоры, conference papers, editorials;","авторы — профили с Author ID;","цитирования — данные о научных ссылках между публикациями."}', '{"manbalar — jurnallar, proceedings, book series;","hujjatlar — maqolalar, sharhlar, conference papers, editorials;","mualliflar — Author ID ga ega profillar;","iqtiboslar — nashrlar o‘rtasidagi ilmiy havolalar haqidagi ma’lumotlar."}', '{"sources — journals, proceedings, book series;","documents — articles, reviews, conference papers, editorials;","authors — profiles with Author ID;","citations — data about scholarly references between publications."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anz3001vwrk1do59ntk1', 'cmrq0anz2001swrk1ijyhvkzj', 2, 'LIST', 'Scopus нужен авторам и организациям, чтобы', 'Scopus mualliflar va tashkilotlarga quyidagilar uchun kerak', 'Scopus is used by authors and institutions to', NULL, NULL, NULL, '{"проверить, индексируется ли журнал;","посмотреть метрики журнала;","найти публикации автора;","оценить цитируемость;","анализировать научную результативность."}', '{"jurnal indekslanadimi-yo‘qmi tekshirish;","jurnal metrikalarini ko‘rish;","muallif nashrlarini topish;","iqtiboslilikni baholash;","ilmiy natijadorlikni tahlil qilish."}', '{"check whether a journal is indexed;","view journal metrics;","find an author’s publications;","evaluate citations;","analyze research performance."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anz3001wwrk1dprn51t3', 'cmrq0anz2001swrk1ijyhvkzj', 3, 'PARAGRAPH', NULL, NULL, NULL, 'Важно понимать разницу между журналом и статьёй. Если журнал индексируется в Scopus, это ещё не означает, что каждая новая статья появится там сразу. Индексация статьи зависит от передачи метаданных издателем и последующей обработки в базе.', 'Jurnal bilan maqola o‘rtasidagi farqni tushunish muhim. Agar jurnal Scopus’da indekslansa ham, bu har bir yangi maqola darhol bazada paydo bo‘ladi degani emas. Maqolaning indekslanishi nashriyot metadata yuborishi va keyinchalik bazada qayta ishlanishiga bog‘liq.', 'It is important to understand the difference between a journal and an article. If a journal is indexed in Scopus, it does not mean every new article will appear there immediately. Indexing of an article depends on metadata delivery by the publisher and subsequent processing in the database.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anz3001xwrk1pe9pck22', 'cmrq0anz2001swrk1ijyhvkzj', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Также Scopus использует систему отбора и переоценки источников. Поэтому наличие журнала в базе связано не только с подачей данных, но и с требованиями к качеству, регулярности и публикационной политике.', 'Shuningdek, Scopus manbalarni tanlash va qayta baholash tizimidan foydalanadi. Shu sababli jurnalning bazada mavjudligi faqat ma’lumot yuborishga emas, balki sifat, muntazamlik va nashr siyosati talablariga ham bog‘liq.', 'Scopus also uses a system of source selection and reevaluation. Therefore, a journal’s presence in the database depends not only on submitted data but also on requirements for quality, regularity, and publication policy.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anz3001ywrk1wciyok69', 'cmrq0anz2001swrk1ijyhvkzj', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Scopus — это не просто список журналов, а полноценная научная база с аналитикой по источникам, авторам и цитированиям.', 'Scopus shunchaki jurnallar ro‘yxati emas, balki manbalar, mualliflar va iqtiboslar bo‘yicha analitikaga ega to‘liq ilmiy bazadir.', 'Scopus is not just a list of journals but a full scholarly database with analytics on sources, authors, and citations.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzg0020wrk1dvkqlr6s', 'cmrq0anzf001zwrk1lvakvk1y', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Квартиль — это относительный показатель. Он помогает понять, насколько высоко журнал стоит внутри своей предметной области по сравнению с другими журналами той же категории.', 'Kvartil nisbiy ko‘rsatkichdir. U jurnalning o‘z fan sohasida shu kategoriya doirasidagi boshqa jurnallarga nisbatan qanchalik yuqori o‘rinda turganini tushunishga yordam beradi.', 'A quartile is a relative indicator. It helps understand how highly a journal stands within its subject area compared to other journals in the same category.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzg0021wrk1i1kn7vrg', 'cmrq0anzf001zwrk1lvakvk1y', 1, 'LIST', 'Обычно квартиль понимают так', 'Odatda kvartil quyidagicha tushuniladi', 'Quartiles are usually understood as follows', NULL, NULL, NULL, '{"Q1 — лучшие 25% журналов категории;","Q2 — 25–50%;","Q3 — 50–75%;","Q4 — 75–100%."}', '{"Q1 — kategoriyadagi eng yaxshi 25% jurnallar;","Q2 — 25–50%;","Q3 — 50–75%;","Q4 — 75–100%."}', '{"Q1 — the best 25% of journals in the category;","Q2 — 25–50%;","Q3 — 50–75%;","Q4 — 75–100%."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzg0022wrk1jcl8km4t', 'cmrq0anzf001zwrk1lvakvk1y', 2, 'LIST', 'Почему это важно', 'Bu nima uchun muhim', 'Why this is important', NULL, NULL, NULL, '{"авторы ориентируются на квартиль при выборе журнала;","некоторые университеты и комиссии учитывают квартиль в отчётности;","он помогает быстро оценить уровень журнала внутри конкретной области."}', '{"mualliflar jurnal tanlashda kvartilga qaraydilar;","ayrim universitetlar va komissiyalar hisobotda kvartilni hisobga oladi;","u ma’lum soha ichida jurnal darajasini tez baholashga yordam beradi."}', '{"authors use quartile when choosing a journal;","some universities and commissions consider quartiles in reporting;","it helps quickly assess a journal’s level within a particular field."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzg0023wrk1yl69dl8r', 'cmrq0anzf001zwrk1lvakvk1y', 3, 'PARAGRAPH', 'Что важно учитывать', 'Nimani hisobga olish muhim', 'What is important to consider', 'Квартиль относится к журналу, а не к статье. Сильная статья может выйти и не в Q1-журнале, а слабая — даже в более высоком квартиле.', 'Kvartil maqolaga emas, jurnalga tegishli. Kuchli maqola Q1 bo‘lmagan jurnalda ham chiqishi mumkin, zaif maqola esa yuqoriroq kvartilda ham uchrashi mumkin.', 'Quartile refers to the journal, not the article. A strong paper may appear in a non-Q1 journal, and a weak paper may appear even in a higher-quartile journal.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzg0024wrk11go0x1zm', 'cmrq0anzf001zwrk1lvakvk1y', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Один журнал может иметь несколько категорий. Если журнал относится сразу к нескольким научным областям, его позиции в них могут отличаться.', 'Bitta jurnal bir nechta kategoriyaga ega bo‘lishi mumkin. Agar jurnal bir vaqtning o‘zida bir nechta ilmiy sohaga tegishli bo‘lsa, ularning har birida pozitsiyasi farq qilishi mumkin.', 'A journal may have several categories. If it belongs to multiple subject areas, its positions in them may differ.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzg0025wrk1tc2r42i8', 'cmrq0anzf001zwrk1lvakvk1y', 5, 'PARAGRAPH', NULL, NULL, NULL, 'Квартиль может меняться. Метрики обновляются, и журнал может перейти из Q2 в Q1 или наоборот.', 'Kvartil o‘zgarishi mumkin. Metrikalar yangilanadi va jurnal Q2 dan Q1 ga yoki aksincha o‘tishi mumkin.', 'A quartile can change. Metrics are updated, and a journal may move from Q2 to Q1 or vice versa.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzg0026wrk15onnruyz', 'cmrq0anzf001zwrk1lvakvk1y', 6, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Квартиль — это позиция журнала внутри его категории, а не абсолютная оценка качества любой статьи в нём.', 'Kvartil — bu jurnalning o‘z kategoriyasidagi o‘rni, undagi har qanday maqola sifatining mutlaq bahosi emas.', 'A quartile is the position of a journal within its category, not an absolute assessment of the quality of every article in it.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzo0028wrk1wdir90h8', 'cmrq0anzm0027wrk1w2p7ig1l', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Google Scholar Profiles позволяют автору собрать свои работы в одном профиле и отслеживать, как часто на них ссылаются другие публикации.', 'Google Scholar Profiles muallifga o‘z ishlarini bitta profilda jamlash va ularga boshqa nashrlar qanchalik tez-tez havola qilayotganini kuzatish imkonini beradi.', 'Google Scholar Profiles allow an author to gather works in one profile and track how often they are cited by other publications.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzo0029wrk12mqjlr91', 'cmrq0anzm0027wrk1w2p7ig1l', 1, 'LIST', 'Система автоматически считает', 'Tizim avtomatik ravishda hisoblaydi', 'The system automatically calculates', NULL, NULL, NULL, '{"total citations — общее число цитирований;",h-index;,i10-index;,"отдельные показатели для всего периода и для последних лет."}', '{"total citations — umumiy iqtiboslar soni;",h-index;,i10-index;,"butun davr va so‘nggi yillar uchun alohida ko‘rsatkichlar."}', '{"total citations — total number of citations;",h-index;,i10-index;,"separate indicators for the whole period and recent years."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzo002awrk13kgppqab', 'cmrq0anzm0027wrk1w2p7ig1l', 2, 'PARAGRAPH', 'Что означает h-индекс', 'h-indeks nimani anglatadi', 'What h-index means', 'Если у автора h-index = 10, это значит, что у него есть как минимум 10 публикаций, каждая из которых была процитирована не менее 10 раз.', 'Agar muallifning h-index’i 10 bo‘lsa, bu uning kamida 10 ta nashri borligini va ularning har biri kamida 10 martadan iqtibos qilinganini anglatadi.', 'If an author has an h-index of 10, it means the author has at least 10 publications, each cited at least 10 times.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzo002bwrk19frxfm83', 'cmrq0anzm0027wrk1w2p7ig1l', 3, 'PARAGRAPH', 'Почему h-индекс в Google Scholar часто выше', 'Nega Google Scholar’dagi h-indeks ko‘pincha yuqoriroq', 'Why h-index in Google Scholar is often higher', 'Google Scholar индексирует очень широкий круг источников: статьи, материалы конференций, диссертации, репозитории, некоторые книги и главы, а также версии научных текстов, размещённые в сети.', 'Google Scholar juda keng doiradagi manbalarni indekslaydi: maqolalar, konferensiya materiallari, dissertatsiyalar, repozitoriylar, ayrim kitoblar va bo‘limlar, shuningdek internetda joylashtirilgan ilmiy matn versiyalari.', 'Google Scholar indexes a very broad range of sources: articles, conference materials, dissertations, repositories, some books and chapters, and versions of scholarly texts posted online.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzo002cwrk1qlwmhnap', 'cmrq0anzm0027wrk1w2p7ig1l', 4, 'LIST', 'Из-за этого платформа часто показывает', 'Shu sababli platforma ko‘pincha quyidagilarni ko‘rsatadi', 'Because of this, the platform often shows', NULL, NULL, NULL, '{"больше публикаций;","больше цитирований;","более высокий h-индекс, чем более строгие базы вроде Scopus."}', '{"ko‘proq nashrlar;","ko‘proq iqtiboslar;","Scopus kabi qat’iyroq bazalarga nisbatan balandroq h-indeks."}', '{"more publications;","more citations;","a higher h-index than stricter databases such as Scopus."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzo002dwrk1t7v10bpp', 'cmrq0anzm0027wrk1w2p7ig1l', 5, 'PARAGRAPH', 'Что важно учитывать', 'Nimani hisobga olish kerak', 'What is important to consider', 'Google Scholar удобен, но не всегда идеально чист с точки зрения метаданных. Иногда в профиль могут попадать лишние публикации, дубликаты или статьи других авторов с похожим именем. Поэтому профиль нужно периодически проверять вручную.', 'Google Scholar qulay, ammo metadata nuqtai nazaridan har doim ham ideal darajada toza emas. Ba’zan profilga ortiqcha nashrlar, dublikatlar yoki ismi o‘xshash boshqa mualliflarning maqolalari tushib qolishi mumkin. Shuning uchun profilni vaqti-vaqti bilan qo‘lda tekshirib turish kerak.', 'Google Scholar is convenient, but from a metadata perspective it is not always perfectly clean. Sometimes extra publications, duplicates, or articles by other authors with similar names may appear in the profile. Therefore, the profile should be checked manually from time to time.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzo002ewrk1mtjpews8', 'cmrq0anzm0027wrk1w2p7ig1l', 6, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'h-индекс в Google Scholar полезен для общей видимости научного профиля, но его нужно воспринимать с учётом широкой и не всегда идеально точной индексации.', 'Google Scholar’dagi h-indeks ilmiy profilning umumiy ko‘rinishi uchun foydali, ammo uni keng va har doim ham mutlaqo aniq bo‘lmagan indeksatsiyani hisobga olgan holda talqin qilish kerak.', 'The h-index in Google Scholar is useful for general visibility of a research profile, but it should be interpreted with the broad and not always perfectly accurate indexing in mind.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzt002gwrk1m1gpjjwc', 'cmrq0anzt002fwrk1cco2wjpl', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Scopus формирует авторский профиль и на его основе показывает ключевые показатели: количество документов, число цитирований, научные области, Scopus Author ID и h-index.', 'Scopus muallif profilini shakllantiradi va uning asosida asosiy ko‘rsatkichlarni ko‘rsatadi: hujjatlar soni, iqtiboslar soni, ilmiy sohalar, Scopus Author ID va h-index.', 'Scopus creates an author profile and on that basis shows key indicators: number of documents, citations, subject areas, Scopus Author ID, and h-index.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzt002hwrk1a4hwo4f1', 'cmrq0anzt002fwrk1cco2wjpl', 1, 'PARAGRAPH', NULL, NULL, NULL, 'Смысл h-индекса здесь такой же, как и в других системах: если у автора h-index = 8, это значит, что у него есть как минимум 8 публикаций, каждая из которых процитирована не менее 8 раз.', 'Bu yerda h-indeksning ma’nosi boshqa tizimlardagidek: agar muallifning h-index’i 8 bo‘lsa, bu uning kamida 8 ta nashri borligini va ularning har biri kamida 8 martadan iqtibos qilinganini anglatadi.', 'The meaning of the h-index here is the same as in other systems: if an author has an h-index of 8, it means the author has at least 8 publications, each cited at least 8 times.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzt002iwrk11nby2u0k', 'cmrq0anzt002fwrk1cco2wjpl', 2, 'LIST', 'Главное отличие Scopus в том, что', 'Scopus’ning asosiy farqi shundaki', 'The main difference of Scopus is that', NULL, NULL, NULL, '{"учитываются только документы, попавшие в Scopus;","учитываются только те цитирования, которые видит Scopus;","итог зависит от корректности авторского профиля."}', '{"faqat Scopus’ga tushgan hujjatlar hisobga olinadi;","faqat Scopus ko‘radigan iqtiboslar hisobga olinadi;","yakuniy natija muallif profilining to‘g‘riligiga bog‘liq."}', '{"only documents included in Scopus are counted;","only citations seen by Scopus are counted;","the result depends on the correctness of the author profile."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzt002jwrk1ihn7sowc', 'cmrq0anzt002fwrk1cco2wjpl', 3, 'LIST', 'Иногда у автора в Scopus бывают проблемы', 'Ba’zan muallifda Scopus’da quyidagi muammolar bo‘ladi', 'Sometimes authors in Scopus have problems', NULL, NULL, NULL, '{"часть публикаций не прикреплена;","профиль разделён на несколько карточек;","в профиль попали чужие документы;","статья есть в базе, но не отображается у нужного автора."}', '{"nashrlarning bir qismi biriktirilmagan bo‘ladi;","profil bir nechta kartochkaga bo‘linib ketgan bo‘ladi;","profilga boshqa birovning hujjatlari tushib qoladi;","maqola bazada bo‘ladi, lekin kerakli muallifda ko‘rinmaydi."}', '{"some publications are not attached;","the profile is split into several records;","other people’s documents appear in the profile;","the article is in the database but does not appear under the correct author."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzt002kwrk19e3uk3hx', 'cmrq0anzt002fwrk1cco2wjpl', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Поэтому h-индекс в Scopus полезен не только как метрика, но и как сигнал: если он выглядит странно, стоит проверить сам профиль автора.', 'Shu sababli Scopus’dagi h-indeks nafaqat metrika, balki signal sifatida ham foydalidir: agar u g‘alati ko‘rinsa, muallif profilining o‘zini tekshirish kerak.', 'Therefore, the h-index in Scopus is useful not only as a metric but also as a signal: if it looks unusual, the author profile itself should be checked.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0anzt002lwrk1d1ffbgs5', 'cmrq0anzt002fwrk1cco2wjpl', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'h-индекс в Scopus — это показатель по данным самой базы Scopus, поэтому он может отличаться от других платформ.', 'Scopus’dagi h-indeks aynan Scopus bazasi ma’lumotlariga asoslangan ko‘rsatkichdir, shu sababli u boshqa platformalardan farq qilishi mumkin.', 'The h-index in Scopus is a metric based on Scopus database data itself, so it may differ from other platforms.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002nwrk1t93li2p5', 'cmrq0anzz002mwrk1v0f53ih9', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Многие авторы сравнивают свои показатели в разных системах и удивляются, почему цифры отличаются. Это нормально: базы работают по разным принципам.', 'Ko‘plab mualliflar turli tizimlardagi ko‘rsatkichlarini taqqoslab, nega sonlar farq qilishiga hayron bo‘ladilar. Bu tabiiy holat: bazalar turli tamoyillar asosida ishlaydi.', 'Many authors compare their metrics across systems and wonder why the numbers differ. This is normal: the databases operate on different principles.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002owrk1h57vf9nx', 'cmrq0anzz002mwrk1v0f53ih9', 1, 'PARAGRAPH', 'Google Scholar', 'Google Scholar', 'Google Scholar', 'Google Scholar индексирует большой массив научного контента из интернета: журнальные статьи, материалы конференций, диссертации, репозитории, рукописи на университетских сайтах, а иногда и разные версии одной и той же работы.', 'Google Scholar internetdagi katta hajmdagi ilmiy kontentni indekslaydi: jurnal maqolalari, konferensiya materiallari, dissertatsiyalar, repozitoriylar, universitet saytlaridagi qo‘lyozmalar va ba’zan bir ishning turli versiyalarini ham.', 'Google Scholar indexes a large body of scholarly content from the internet: journal articles, conference materials, dissertations, repositories, manuscripts on university websites, and sometimes different versions of the same work.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002pwrk15to6qbwc', 'cmrq0anzz002mwrk1v0f53ih9', 2, 'LIST', 'Из-за этого Google Scholar часто показывает', 'Shu sababli Google Scholar ko‘pincha quyidagilarni ko‘rsatadi', 'Because of this, Google Scholar often shows', NULL, NULL, NULL, '{"больше публикаций;","больше цитирований;","более высокий h-индекс."}', '{"ko‘proq nashrlar;","ko‘proq iqtiboslar;","yuqoriroq h-indeks."}', '{"more publications;","more citations;","a higher h-index."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002qwrk19cn8buwi', 'cmrq0anzz002mwrk1v0f53ih9', 3, 'PARAGRAPH', 'Scopus', 'Scopus', 'Scopus', 'Scopus работает более строго: включает только отобранные источники, учитывает свои собственные профили авторов и считает цитирования внутри своей базы.', 'Scopus qat’iyroq ishlaydi: faqat tanlab olingan manbalarni qamrab oladi, o‘zining muallif profillarini yuritadi va iqtiboslarni o‘z bazasi ichida hisoblaydi.', 'Scopus operates more strictly: it includes only selected sources, uses its own author profiles, and counts citations within its own database.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002rwrk10zw1loxh', 'cmrq0anzz002mwrk1v0f53ih9', 4, 'LIST', 'В результате у автора в Scopus обычно', 'Natijada Scopus’da muallifda odatda', 'As a result, in Scopus an author usually has', NULL, NULL, NULL, '{"меньше публикаций;","меньше цитат;","более консервативный h-индекс."}', '{"kamroq nashrlar;","kamroq iqtiboslar;","konservativroq h-indeks."}', '{"fewer publications;","fewer citations;","a more conservative h-index."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002swrk1zhsbs296', 'cmrq0anzz002mwrk1v0f53ih9', 5, 'PARAGRAPH', 'Что это значит на практике', 'Bu amalda nimani anglatadi', 'What this means in practice', 'Нельзя просто взять цифру из Google Scholar и ожидать, что она совпадёт со Scopus. Это не ошибка и не обязательно проблема в профиле. Чаще всего это следствие разной политики индексации.', 'Google Scholar’dagi raqamni olib, u Scopus bilan aynan bir xil bo‘lishini kutib bo‘lmaydi. Bu xato ham emas, profil muammosi ham bo‘lishi shart emas. Ko‘pincha bu turli indeksatsiya siyosatining natijasidir.', 'You cannot simply take a number from Google Scholar and expect it to match Scopus. This is not necessarily an error or a profile problem. Most often it is a result of different indexing policies.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002twrk1baz2kbmg', 'cmrq0anzz002mwrk1v0f53ih9', 6, 'LIST', 'Что использовать', 'Nimadan foydalanish kerak', 'What to use', NULL, NULL, NULL, '{"Google Scholar полезен для широкой видимости и общего представления о цитируемости.","Scopus чаще используют для формальной аналитики, отчётности и оценки индексируемых публикаций."}', '{"Google Scholar keng ko‘rinuvchanlik va iqtiboslilik haqida umumiy tasavvur uchun foydali.","Scopus ko‘proq rasmiy tahlil, hisobot va indekslanadigan nashrlarni baholashda qo‘llanadi."}', '{"Google Scholar is useful for broad visibility and a general view of citation impact.","Scopus is more often used for formal analytics, reporting, and evaluation of indexed publications."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao00002uwrk1ox7zjyce', 'cmrq0anzz002mwrk1v0f53ih9', 7, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Если h-индекс в Google Scholar выше, чем в Scopus, это обычная ситуация, а не признак ошибки сам по себе.', 'Agar Google Scholar’dagi h-indeks Scopus’dagidan yuqori bo‘lsa, bu odatiy holat bo‘lib, o‘z-o‘zidan xato belgisi emas.', 'If the h-index in Google Scholar is higher than in Scopus, this is a normal situation and not by itself a sign of an error.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao09002wwrk13od80qj8', 'cmrq0ao08002vwrk10wu96a4g', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Когда говорят «журнал ВАК» или «журнал ОАК», обычно имеют в виду, что издание входит в официальный список рекомендованных научных изданий. Такой статус особенно важен для тех, кто готовит диссертацию или работает в системе академической аттестации.', '«VAK jurnali» yoki «OAK jurnali» deyilganda, odatda nashr tavsiya etilgan ilmiy jurnallarning rasmiy ro‘yxatiga kirgani nazarda tutiladi. Bunday maqom ayniqsa dissertatsiya tayyorlayotganlar yoki akademik attestatsiya tizimida ishlayotganlar uchun muhim.', 'When people say “VAK journal” or “OAK journal,” they usually mean that the publication is included in the official list of recommended scientific journals. This status is especially important for those preparing a dissertation or working within the academic attestation system.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao09002xwrk1wy8t6fni', 'cmrq0ao08002vwrk10wu96a4g', 1, 'LIST', 'Для автора значение этого статуса в том, что публикация может учитываться', 'Muallif uchun bu maqomning ahamiyati shundaki, nashr quyidagi holatlarda hisobga olinishi mumkin', 'For an author, this status matters because the publication may be counted', NULL, NULL, NULL, '{"при защите диссертации;","при отчётности по научной работе;","при подтверждении публикационной активности;","в требованиях отдельных научных и образовательных структур."}', '{"dissertatsiya himoyasida;","ilmiy ish bo‘yicha hisobotlarda;","nashr faolligini tasdiqlashda;","ayrim ilmiy va ta’lim tuzilmalari talablarida."}', '{"during dissertation defense;","in research reporting;","when confirming publication activity;","in the requirements of certain scientific and educational bodies."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao09002ywrk1vsb1333i', 'cmrq0ao08002vwrk10wu96a4g', 2, 'PARAGRAPH', 'Нельзя доверять только словам журнала', 'Faqat jurnalning o‘z so‘ziga ishonib bo‘lmaydi', 'Do not rely only on the journal’s own claim', 'Если на сайте журнала написано, что он «входит в перечень ВАК/ОАК», это желательно проверять по официальному источнику, а не по рекламному описанию.', 'Agar jurnal saytida u «VAK/OAK ro‘yxatiga kiradi» deb yozilgan bo‘lsa, buni reklama matni orqali emas, rasmiy manba orqali tekshirish kerak.', 'If a journal website says that it “is included in the VAK/OAK list,” this should be checked against an official source rather than taken from a promotional description.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao09002zwrk1sygwbkzd', 'cmrq0ao08002vwrk10wu96a4g', 3, 'PARAGRAPH', 'Перечни могут обновляться', 'Ro‘yxatlar yangilanib turadi', 'Lists may be updated', 'Журнал мог входить в список раньше, но его текущий статус надо проверять по актуальной версии перечня или по официальному сайту уполномоченного органа.', 'Jurnal ilgari ro‘yxatda bo‘lgan bo‘lishi mumkin, ammo uning hozirgi maqomini ro‘yxatning amaldagi versiyasi yoki vakolatli organning rasmiy sayti orqali tekshirish kerak.', 'A journal may have been in the list earlier, but its current status should be checked against the current version of the list or the official website of the authorized body.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao090030wrk1kdqrc0at', 'cmrq0ao08002vwrk10wu96a4g', 4, 'PARAGRAPH', 'ВАК/ОАК и Scopus — это разное', 'VAK/OAK va Scopus — bu boshqa-boshqa tizimlar', 'VAK/OAK and Scopus are different', 'Журнал может входить в перечень ВАК/ОАК, но не индексироваться в Scopus; индексироваться в Scopus, но не быть в перечне ВАК/ОАК. Это разные системы признания и разные задачи.', 'Jurnal VAK/OAK ro‘yxatida bo‘lishi, lekin Scopus’da indekslanmasligi mumkin; yoki aksincha Scopus’da bo‘lib, VAK/OAK ro‘yxatida bo‘lmasligi mumkin. Bu tan olishning turli tizimlari va turli vazifalardir.', 'A journal may be included in the VAK/OAK list but not indexed in Scopus, or it may be indexed in Scopus but not included in the VAK/OAK list. These are different recognition systems with different purposes.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao090031wrk1l5bjepgz', 'cmrq0ao08002vwrk10wu96a4g', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Статус ВАК/ОАК надо проверять по официальному перечню и по дате проверки, а не только по информации на сайте журнала.', 'VAK/OAK maqomini faqat jurnal saytiga qarab emas, balki rasmiy ro‘yxat va tekshirish sanasi bo‘yicha aniqlash kerak.', 'VAK/OAK status should be checked using the official list and the date of verification, not only the information on the journal’s website.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0d0033wrk1pn7c6hnk', 'cmrq0ao0d0032wrk1rdpgw7sl', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Авторы часто воспринимают публикацию как один момент: «статья вышла». На практике у статьи есть несколько последовательных стадий, и каждая из них имеет свой статус.', 'Mualliflar ko‘pincha nashrni bir lahza sifatida qabul qiladilar: «maqola chiqdi». Amalda esa maqolaning ketma-ket bir necha bosqichi bo‘ladi va har birining o‘z maqomi bor.', 'Authors often perceive publication as a single moment: “the article came out.” In practice, an article has several successive stages, and each has its own status.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0d0034wrk1uuvfszig', 'cmrq0ao0d0032wrk1rdpgw7sl', 1, 'LIST', 'Основные стадии', 'Asosiy bosqichlar', 'Main stages', NULL, NULL, NULL, '{"1. Подача рукописи — автор отправляет статью через editorial system журнала.","2. Первичная редакционная проверка — проверяют тему, комплектность файлов, технические требования, этику и оформление.","3. Назначение редактора — рукопись получает редактор или член редколлегии.","4. Peer review — статья уходит внешним рецензентам.","5. Решение — reject, minor revision, major revision или accept.","6. Производственный этап — copyediting, typesetting, proofing и подготовка к публикации.","7. Online first / Article in Press — статья появляется на сайте раньше окончательного выпуска.","8. Финальная публикация — статья закрепляется за томом, выпуском, страницами или другой финальной формой.","9. Появление в Scopus — после передачи данных издателем и обработки записи статья появляется как индексируемый документ в базе."}', '{"1. Qo‘lyozmani topshirish — muallif maqolani jurnalning editorial system’i orqali yuboradi.","2. Dastlabki tahririy tekshiruv — mavzu, fayllar to‘liqligi, texnik talablar, etika va rasmiylashtirish tekshiriladi.","3. Muharrir tayinlash — qo‘lyozma muharrir yoki tahrir hay’ati a’zosiga beriladi.","4. Peer review — maqola tashqi taqrizchilarga yuboriladi.","5. Qaror — reject, minor revision, major revision yoki accept.","6. Ishlab chiqarish bosqichi — copyediting, typesetting, proofing va nashrga tayyorlash.","7. Online first / Article in Press — maqola yakuniy sondan oldin saytda chiqadi.","8. Yakuniy nashr — maqola tom, son, sahifalar yoki boshqa yakuniy shaklga biriktiriladi.","9. Scopus’da paydo bo‘lish — nashriyot ma’lumot yuborgani va yozuv qayta ishlangandan keyin maqola bazada indekslanadigan hujjat sifatida ko‘rinadi."}', '{"1. Manuscript submission — the author sends the article through the journal’s editorial system.","2. Initial editorial screening — the topic, completeness of files, technical requirements, ethics, and formatting are checked.","3. Editor assignment — the manuscript is assigned to an editor or editorial board member.","4. Peer review — the article goes to external reviewers.","5. Decision — reject, minor revision, major revision, or accept.","6. Production stage — copyediting, typesetting, proofing, and preparation for publication.","7. Online first / Article in Press — the article appears online before final issue assignment.","8. Final publication — the article is assigned to a volume, issue, pages, or another final publication form.","9. Appearance in Scopus — after metadata transfer by the publisher and record processing, the article appears as an indexed document in the database."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0d0035wrk11vnholgf', 'cmrq0ao0d0032wrk1rdpgw7sl', 2, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Статусы «принята», «опубликована онлайн», «вышла в номере» и «проиндексировалась в Scopus» — это не одно и то же.', '«Qabul qilingan», «onlayn chop etilgan», «sonda chiqqan» va «Scopus’da indekslangan» maqomlari bir xil narsa emas.', 'The statuses “accepted,” “published online,” “assigned to an issue,” and “indexed in Scopus” are not the same thing.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0k0037wrk1m2a5qgl3', 'cmrq0ao0k0036wrk1xvj7xujx', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Под частотой публикации обычно понимают график работы журнала. Например: monthly, bimonthly, quarterly, semiannual, annual, continuous publication.', 'Nashr chastotasi deganda odatda jurnalning ish jadvali tushuniladi. Masalan: monthly, bimonthly, quarterly, semiannual, annual, continuous publication.', 'Publication frequency usually means the working schedule of a journal. For example: monthly, bimonthly, quarterly, semiannual, annual, or continuous publication.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0k0038wrk1nh3z18mf', 'cmrq0ao0k0036wrk1xvj7xujx', 1, 'LIST', 'Для автора это важно по двум причинам', 'Bu muallif uchun ikki sababga ko‘ra muhim', 'This matters to an author for two reasons', NULL, NULL, NULL, '{"1. Частота влияет на ожидания по срокам.","2. Частота говорит о стабильности источника."}', '{"1. Chastota muddatlar bo‘yicha kutilmalarga ta’sir qiladi.","2. Chastota manbaning barqarorligi haqida ma’lumot beradi."}', '{"1. Frequency affects expectations about timing.","2. Frequency says something about source stability."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0k0039wrk172bznavr', 'cmrq0ao0k0036wrk1xvj7xujx', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Если журнал выходит два раза в год, то даже после принятия статьи финальное включение в выпуск может занять больше времени, чем в ежемесячном журнале.', 'Agar jurnal yiliga ikki marta chiqsa, maqola qabul qilingandan keyin ham uni yakuniy songa kiritish har oy chiqadigan jurnaldagidan ko‘proq vaqt olishi mumkin.', 'If a journal is published twice a year, then even after acceptance the final placement of an article into an issue may take longer than in a monthly journal.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0k003awrk1czxvndqu', 'cmrq0ao0k0036wrk1xvj7xujx', 3, 'PARAGRAPH', NULL, NULL, NULL, 'Для научного журнала регулярность выпуска — важный признак нормальной издательской работы. В требованиях Scopus регулярность публикации тоже имеет значение.', 'Ilmiy jurnal uchun sonlarning muntazam chiqishi normal nashriyot ishining muhim belgisidir. Scopus talablarida ham nashr muntazamligi ahamiyatga ega.', 'For a scientific journal, regularity of publication is an important sign of normal publishing practice. In Scopus requirements, publication regularity also matters.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0k003bwrk1ezpemg7u', 'cmrq0ao0k0036wrk1xvj7xujx', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Но есть важное уточнение: сегодня многие журналы работают не только по модели «номер за номером». Статья может сначала появиться онлайн, а потом уже попасть в выпуск.', 'Ammo muhim aniqlik bor: bugun ko‘plab jurnallar faqat «sondan songa» modeli bo‘yicha ishlamaydi. Maqola avval onlayn chiqib, keyin songa kiritilishi mumkin.', 'But there is an important clarification: today many journals do not work only under an “issue by issue” model. An article may appear online first and only later be assigned to an issue.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0k003cwrk1axkb963x', 'cmrq0ao0k0036wrk1xvj7xujx', 5, 'LIST', 'Что это значит для автора', 'Bu muallif uchun nimani anglatadi', 'What this means for the author', NULL, NULL, NULL, '{"график журнала не гарантирует мгновенную публикацию;","низкая частота не всегда плоха;","online first может ускорить появление статьи на сайте, даже если выпуск выйдет позже;","реальный срок зависит не только от периодичности, но и от редакционного цикла."}', '{"jurnal jadvali darhol nashrni kafolatlamaydi;","past chastota har doim ham yomon emas;","online first maqolaning saytda tezroq paydo bo‘lishini ta’minlashi mumkin, hatto son keyinroq chiqsa ham;","haqiqiy muddat nafaqat davriylikka, balki tahririy siklga ham bog‘liq."}', '{"the journal schedule does not guarantee immediate publication;","low frequency is not always bad;","online first may speed up the appearance of the article on the site even if the issue comes later;","the actual timing depends not only on periodicity but also on the editorial cycle."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0k003dwrk1w7dsvi98', 'cmrq0ao0k0036wrk1xvj7xujx', 6, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Частота публикации — это ритм работы журнала, но не точный прогноз даты выхода конкретной статьи.', 'Nashr chastotasi jurnal ishining ritmi, ammo aniq maqolaning chiqish sanasi bo‘yicha aniq prognoz emas.', 'Publication frequency is the rhythm of a journal’s work, not an exact forecast of the release date of a specific article.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0p003fwrk1928seup2', 'cmrq0ao0o003ewrk183wts5mq', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'В Scopus используются разные типы идентификаторов: Author ID — для автора; Source ID — для журнала, серии или другого источника; идентификаторы документа — для конкретной публикации.', 'Scopus’da turli identifikatorlar ishlatiladi: Author ID — muallif uchun; Source ID — jurnal, seriya yoki boshqa manba uchun; hujjat identifikatorlari — aniq nashr uchun.', 'Scopus uses different kinds of identifiers: Author ID for an author; Source ID for a journal, series, or another source; and document identifiers for a specific publication.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0p003gwrk1kx4py4kk', 'cmrq0ao0o003ewrk183wts5mq', 1, 'PARAGRAPH', NULL, NULL, NULL, 'Source ID нужен для точной технической идентификации источника внутри базы. Это особенно полезно, когда у журналов похожие названия, название журнала менялось, нужно сверять данные между разными системами или журнал используется в каталоге, CRM, базе или аналитике.', 'Source ID bazaning ichida manbani aniq texnik identifikatsiya qilish uchun kerak. Bu ayniqsa jurnallarning nomlari o‘xshash bo‘lganda, jurnal nomi o‘zgarganda, turli tizimlar o‘rtasida ma’lumotlarni solishtirish kerak bo‘lganda yoki jurnal katalog, CRM, baza yoki analitikada ishlatilganda foydalidir.', 'Source ID is needed for accurate technical identification of a source within the database. This is especially useful when journals have similar names, when a journal title has changed, when data must be matched across systems, or when a journal is used in a catalog, CRM, database, or analytics.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0p003hwrk1onkup920', 'cmrq0ao0o003ewrk183wts5mq', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Для обычного автора Source ID редко является повседневным инструментом, но для сайта о журналах это очень полезное поле. Оно помогает связывать карточку журнала с конкретной записью в Scopus и уменьшает риск ошибок.', 'Oddiy muallif uchun Source ID kundalik vosita bo‘lib xizmat qilmaydi, ammo jurnallar haqidagi sayt uchun bu juda foydali maydondir. U jurnal kartasini Scopus’dagi aniq yozuv bilan bog‘lashga va xatolar xavfini kamaytirishga yordam beradi.', 'For an ordinary author, Source ID is rarely an everyday tool, but for a journal-focused website it is a very useful field. It helps link a journal card to a specific record in Scopus and reduces the risk of mistakes.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0p003iwrk19i2p2fax', 'cmrq0ao0o003ewrk183wts5mq', 3, 'LIST', 'Важно не путать Source ID с другими идентификаторами', 'Source ID’ni boshqa identifikatorlar bilan aralashtirmaslik kerak', 'It is important not to confuse Source ID with other identifiers', NULL, NULL, NULL, '{"ISSN — это международный номер сериального издания;","DOI — идентификатор статьи или другого объекта;","Source ID — внутренний ключ источника в Scopus."}', '{"ISSN — bu davriy nashrning xalqaro raqami;","DOI — maqola yoki boshqa obyekt identifikatori;","Source ID — Scopus’dagi manbaning ichki kaliti."}', '{"ISSN is the international serial number of a continuing publication;","DOI is an identifier of an article or another object;","Source ID is the internal key of the source in Scopus."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0p003jwrk1tcd0t9a2', 'cmrq0ao0o003ewrk183wts5mq', 4, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Source ID — это идентификатор самого журнала в Scopus, а не статьи и не автора.', 'Source ID — Scopus’dagi jurnalning o‘zi uchun identifikator, maqola yoki muallifniki emas.', 'Source ID is the identifier of the journal itself in Scopus, not of the article and not of the author.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003lwrk1381l6b7s', 'cmrq0ao0t003kwrk1ubgm2967', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Авторы часто называют всё одним словом — «рецензия», но на практике этапы различаются.', 'Mualliflar ko‘pincha hammasini bitta so‘z bilan — «taqriz» deb ataydilar, ammo amalda bosqichlar farqlanadi.', 'Authors often call everything simply “review,” but in practice the stages differ.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003mwrk11rjhl6z0', 'cmrq0ao0t003kwrk1ubgm2967', 1, 'PARAGRAPH', 'Внутренняя проверка', 'Ichki tekshiruv', 'Internal screening', 'Это стартовый этап, когда рукопись просматривает редакция журнала. Здесь оценивают: соответствует ли статья профилю журнала; соблюдены ли требования к оформлению; достаточно ли базового качества; нет ли очевидных проблем с этикой, структурой или подачей.', 'Bu boshlang‘ich bosqich bo‘lib, unda qo‘lyozmani jurnal tahririyati ko‘rib chiqadi. Bu yerda quyidagilar baholanadi: maqola jurnal profiliga mos keladimi; rasmiylashtirish talablari bajarilganmi; dastlabki sifat yetarlimi; etika, tuzilma yoki taqdimot bo‘yicha yaqqol muammolar yo‘qmi.', 'This is the initial stage when the manuscript is screened by the journal editorial office. They evaluate whether the article fits the journal’s scope, whether formatting requirements are met, whether the basic quality is sufficient, and whether there are obvious problems with ethics, structure, or presentation.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003nwrk167zhz3aq', 'cmrq0ao0t003kwrk1ubgm2967', 2, 'LIST', 'Такой этап могут называть', 'Bu bosqich quyidagicha atalishi mumkin', 'This stage may be called', NULL, NULL, NULL, '{"editorial screening;","initial quality check;","desk evaluation."}', '{"editorial screening;","initial quality check;","desk evaluation."}', '{"editorial screening;","initial quality check;","desk evaluation."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003owrk13f33werj', 'cmrq0ao0t003kwrk1ubgm2967', 3, 'PARAGRAPH', NULL, NULL, NULL, 'Иногда статья отклоняется уже здесь, без отправки внешним рецензентам.', 'Ba’zan maqola tashqi taqrizchilarga yuborilmasdan aynan shu bosqichda rad etiladi.', 'Sometimes a paper is rejected already at this stage, without being sent to external reviewers.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003pwrk1g3t7xnjr', 'cmrq0ao0t003kwrk1ubgm2967', 4, 'PARAGRAPH', 'Внешнее рецензирование', 'Tashqi taqriz', 'External peer review', 'Если статья проходит редакционный фильтр, её могут направить профильным экспертам. Именно они оценивают научную новизну, корректность методов, логику результатов, силу выводов и общую научную ценность работы.', 'Agar maqola tahririy filtrdan o‘tsa, u soha bo‘yicha mutaxassis ekspertlarga yuborilishi mumkin. Aynan ular ilmiy yangilikni, metodlarning to‘g‘riligini, natijalar mantiqini, xulosalarning kuchini va ishning umumiy ilmiy qiymatini baholaydilar.', 'If the article passes the editorial filter, it may be sent to subject experts. They evaluate scientific novelty, methodological correctness, the logic of results, the strength of conclusions, and the overall scholarly value of the work.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003qwrk1mdk5tdma', 'cmrq0ao0t003kwrk1ubgm2967', 5, 'LIST', 'Какие бывают модели review', 'Review modellari qanday bo‘ladi', 'What review models exist', NULL, NULL, NULL, '{"single anonymized review;","double anonymized review;","triple anonymized review;","open review."}', '{"single anonymized review;","double anonymized review;","triple anonymized review;","open review."}', '{"single anonymized review;","double anonymized review;","triple anonymized review;","open review."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003rwrk1qbmek9zm', 'cmrq0ao0t003kwrk1ubgm2967', 6, 'PARAGRAPH', NULL, NULL, NULL, 'Для автора важно понимать, что «молчание от рецензентов» не всегда означает задержку. Статья может ещё находиться на внутреннем этапе и даже не быть отправленной на внешнюю экспертизу.', 'Muallif uchun «taqrizchilardan sukut» har doim ham kechikishni anglatmasligini tushunish muhim. Maqola hali ichki bosqichda bo‘lishi va tashqi ekspertizaga umuman yuborilmagan bo‘lishi mumkin.', 'It is important for the author to understand that “silence from reviewers” does not always mean delay. The article may still be at the internal stage and may not even have been sent out for external review yet.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao0u003swrk1vv79fyhn', 'cmrq0ao0t003kwrk1ubgm2967', 7, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Внутренняя проверка отвечает за редакционную пригодность статьи, а внешнее рецензирование — за научную оценку содержания.', 'Ichki tekshiruv maqolaning tahririy yaroqliligi uchun, tashqi taqriz esa mazmunning ilmiy bahosi uchun javob beradi.', 'Internal screening is responsible for editorial suitability, while external peer review is responsible for the scientific evaluation of the content.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao10003uwrk1hvsgln3s', 'cmrq0ao10003twrk12ulf4306', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Один из самых популярных мифов среди авторов — будто существует универсальный допустимый процент совпадений. На практике это неверно.', 'Mualliflar orasidagi eng keng tarqalgan afsonalardan biri — go‘yoki mos tushishlarning universal ruxsat etilgan foizi mavjudligi. Amalda bu noto‘g‘ri.', 'One of the most common myths among authors is that there is a universal acceptable percentage of overlap. In practice, this is not true.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao10003vwrk1mn1vc18y', 'cmrq0ao10003twrk12ulf4306', 1, 'LIST', 'Редакторы смотрят не просто на цифру, а на то', 'Muharrirlar faqat raqamga emas, balki quyidagilarga qaraydilar', 'Editors look not just at the number but at', NULL, NULL, NULL, '{"где именно найдены совпадения;","какие фрагменты совпадают;","это цитаты, общепринятые формулировки или реальные заимствования;","насколько совпадения влияют на оригинальность текста."}', '{"mos tushishlar aynan qayerda topilganiga;","qaysi parchalar mos tushayotganiga;","ular iqtibosmi, odatiy formulirovkami yoki haqiqiy ko‘chirmalarmi;","mos tushishlar matnning originalligiga qanchalik ta’sir qilishiga."}', '{"where exactly the overlaps were found;","which fragments match;","whether they are quotations, conventional phrases, or actual copying;","how much the overlaps affect the originality of the text."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao10003wwrk1b7fc67k1', 'cmrq0ao10003twrk12ulf4306', 2, 'LIST', 'Например', 'Masalan', 'For example', NULL, NULL, NULL, '{"повторяющиеся технические формулировки в методах могут не быть серьёзной проблемой;","большие совпадающие куски введения, обсуждения или выводов уже вызывают вопросы."}', '{"metodlar bo‘limidagi takrorlanuvchi texnik iboralar jiddiy muammo bo‘lmasligi mumkin;","kirish, muhokama yoki xulosalardagi katta mos tushgan bo‘laklar esa savol tug‘diradi."}', '{"repeated technical wording in methods may not be a serious problem;","large matching chunks in the introduction, discussion, or conclusions raise concerns."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao10003xwrk1otulsqdm', 'cmrq0ao10003twrk12ulf4306', 3, 'LIST', 'Чем пользуются журналы', 'Jurnallar nimalardan foydalanadi', 'What journals use', NULL, NULL, NULL, '{iThenticate;,"Crossref Similarity Check."}', '{iThenticate;,"Crossref Similarity Check."}', '{iThenticate;,"Crossref Similarity Check."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao10003ywrk1ed8ac5z5', 'cmrq0ao10003twrk12ulf4306', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Но важно понимать: программа выявляет совпадения, а не выносит окончательный этический вердикт. Решение всегда остаётся за редакцией.', 'Ammo shuni tushunish kerak: dastur mos tushishlarni aniqlaydi, lekin yakuniy etik hukm chiqarmaydi. Qaror har doim tahririyatda qoladi.', 'But it is important to understand: a tool detects overlaps, it does not make the final ethical judgment. The decision always remains with the editorial office.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao10003zwrk1v7messvu', 'cmrq0ao10003twrk12ulf4306', 5, 'LIST', 'Что важно автору', 'Muallif uchun muhim jihatlar', 'What matters for the author', NULL, NULL, NULL, '{"высокий процент не всегда означает плагиат;","низкий процент не всегда означает безопасность;","одинаково важны и цифра, и содержание;","лучше заранее проверять текст на заимствования и аккуратно оформлять цитаты."}', '{"yuqori foiz har doim ham plagiat degani emas;","past foiz har doim ham xavfsizlikni anglatmaydi;","raqam ham, mazmun ham birdek muhim;","matnni oldindan tekshirish va iqtiboslarni ehtiyotkorlik bilan rasmiylashtirish ma’qul."}', '{"a high percentage does not always mean plagiarism;","a low percentage does not always mean safety;","both the number and the content matter;","it is better to check the text in advance and format quotations carefully."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao100040wrk13va1iheg', 'cmrq0ao10003twrk12ulf4306', 6, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Антиплагиат — это не игра в проценты, а проверка того, насколько текст действительно оригинален и корректно оформлен.', 'Antiplagiat foizlar o‘yini emas, balki matn qanchalik original va to‘g‘ri rasmiylashtirilganini tekshirishdir.', 'Antiplagiarism is not a game of percentages, but an assessment of how genuinely original and properly presented a text is.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao150042wrk1a5azb68r', 'cmrq0ao150041wrk1nph1ubge', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Современные журналы всё чаще сталкиваются с использованием ИИ-инструментов при подготовке рукописей. В базовом виде подход такой: использовать ИИ можно, но скрывать это нельзя, если инструмент реально участвовал в создании значимой части текста, анализа или визуального контента.', 'Zamonaviy jurnallar qo‘lyozma tayyorlashda SI vositalaridan foydalanish holatlariga tobora ko‘proq duch kelmoqda. Asosiy yondashuv shunday: SI’dan foydalanish mumkin, ammo agar vosita matn, tahlil yoki vizual kontentning muhim qismini yaratishda haqiqatan qatnashgan bo‘lsa, buni yashirib bo‘lmaydi.', 'Modern journals increasingly encounter the use of AI tools in manuscript preparation. The basic approach is this: AI may be used, but it should not be hidden if the tool actually participated in creating a significant part of the text, analysis, or visual content.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao150043wrk1lh7hhy6x', 'cmrq0ao150041wrk1nph1ubge', 1, 'LIST', 'Что обычно допустимо', 'Odatda nimaga ruxsat beriladi', 'What is usually acceptable', NULL, NULL, NULL, '{"для языкового редактирования;","для улучшения структуры текста;","для черновой формулировки абзацев;","для помощи в техническом анализе, если это раскрыто и проверено автором."}', '{"til tahriri uchun;","matn tuzilmasini yaxshilash uchun;","abzatslarni dastlabki shakllantirish uchun;","agar bu ochiqlansa va muallif tomonidan tekshirilsa, texnik tahlilda yordam uchun."}', '{"for language editing;","for improving text structure;","for drafting paragraphs;","for assistance in technical analysis, if disclosed and verified by the author."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao150044wrk1nnhi59yd', 'cmrq0ao150041wrk1nph1ubge', 2, 'LIST', 'Что считается проблемой', 'Nima muammo hisoblanadi', 'What is considered problematic', NULL, NULL, NULL, '{"указывать ИИ как автора;","скрывать использование ИИ там, где это нужно раскрывать;","вставлять непроверенные факты, ссылки или выводы;","передавать конфиденциальную рукопись в сервисы, которые могут нарушить правила конфиденциальности."}', '{"SI’ni muallif sifatida ko‘rsatish;","oshkor qilish kerak bo‘lgan joyda SI’dan foydalanishni yashirish;","tekshirilmagan faktlar, havolalar yoki xulosalarni kiritish;","maxfiy qo‘lyozmani maxfiylik qoidalarini buzishi mumkin bo‘lgan servislarga yuborish."}', '{"listing AI as an author;","hiding the use of AI where disclosure is required;","including unverified facts, references, or conclusions;","sending a confidential manuscript to services that may violate confidentiality rules."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao150045wrk12an58fep', 'cmrq0ao150041wrk1nph1ubge', 3, 'PARAGRAPH', NULL, NULL, NULL, 'COPE и WAME прямо указывают, что ИИ не может считаться автором и не может нести ответственность за научную публикацию. Ответственность несут только реальные авторы.', 'COPE va WAME SI muallif hisoblanmasligini va ilmiy nashr uchun javobgarlikni zimmasiga ola olmasligini bevosita ko‘rsatadi. Javobgarlik faqat haqiqiy mualliflarda bo‘ladi.', 'COPE and WAME explicitly state that AI cannot be regarded as an author and cannot bear responsibility for a scholarly publication. Responsibility belongs only to real human authors.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao150046wrk1z3x0eb0h', 'cmrq0ao150041wrk1nph1ubge', 4, 'LIST', 'Что делать автору', 'Muallif nima qilishi kerak', 'What the author should do', NULL, NULL, NULL, '{"проверить правила конкретного журнала;","при необходимости указать это в разделе Methods, Disclosure, Acknowledgements или Author Note;","внимательно перепроверить все формулировки, факты и ссылки."}', '{"aniq jurnal qoidalarini tekshirish;","zarur bo‘lsa buni Methods, Disclosure, Acknowledgements yoki Author Note bo‘limida ko‘rsatish;","barcha formulirovkalar, faktlar va havolalarni sinchiklab qayta tekshirish."}', '{"check the rules of the specific journal;","if necessary, disclose this in Methods, Disclosure, Acknowledgements, or an Author Note;","carefully re-check all wording, facts, and references."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao150047wrk1oys11wqo', 'cmrq0ao150041wrk1nph1ubge', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'ИИ — это инструмент, а не соавтор. Пользоваться им можно только с прозрачным раскрытием и полной проверкой результата.', 'SI — bu vosita, hammuallif emas. Undan faqat shaffof oshkor qilish va natijani to‘liq tekshirish bilan foydalanish mumkin.', 'AI is a tool, not a co-author. It may be used only with transparent disclosure and full verification of the result.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1b0049wrk1tz3e304x', 'cmrq0ao1a0048wrk1oher4nyn', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Во многих современных журналах публикация идёт поэтапно. После принятия и базовой издательской подготовки статья может быть размещена онлайн до того, как получит окончательное место в выпуске.', 'Ko‘plab zamonaviy jurnallarda nashr bosqichma-bosqich amalga oshadi. Maqola qabul qilingach va dastlabki nashriyot tayyorlovidan so‘ng, u yakuniy son joyiga ega bo‘lishidan oldin onlayn joylashtirilishi mumkin.', 'In many modern journals, publication proceeds in stages. After acceptance and basic publisher preparation, the article may be placed online before it receives its final place in an issue.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1b004awrk1291eg1zj', 'cmrq0ao1a0048wrk1oher4nyn', 1, 'LIST', 'Такая публикация означает, что статья уже', 'Bunday nashr shuni anglatadiki, maqola allaqachon', 'Such publication means that the article has already', NULL, NULL, NULL, '{"прошла рецензирование;","принята редакцией;","подготовлена к публичному размещению;","доступна читателям."}', '{"taqrizdan o‘tgan;","tahririyat tomonidan qabul qilingan;","ommaviy joylashtirishga tayyorlangan;","o‘quvchilar uchun ochiq."}', '{"passed peer review;","been accepted by the editorial office;","been prepared for public posting;","become available to readers."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1b004bwrk1t5txuwp9', 'cmrq0ao1a0048wrk1oher4nyn', 2, 'LIST', 'Но это ещё не всегда финальная версия записи', 'Lekin bu har doim ham yakuniy versiya emas', 'But this is not always the final version of record', NULL, NULL, NULL, '{"могут отсутствовать окончательные страницы;","финальная вёрстка;","том и номер;","полное оформление supplementary materials;","окончательная версия ссылок и навигации."}', '{"yakuniy sahifalar bo‘lmasligi mumkin;","yakuniy maket bo‘lmasligi mumkin;","tom va son bo‘lmasligi mumkin;","supplementary materials to‘liq rasmiylashtirilmagan bo‘lishi mumkin;","havolalar va navigatsiyaning yakuniy versiyasi bo‘lmasligi mumkin."}', '{"final page numbers may be missing;","final layout may be missing;","volume and issue may be absent;","supplementary materials may not yet be fully finalized;","the final version of links and navigation may still be pending."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1b004cwrk1cxgcw6x8', 'cmrq0ao1a0048wrk1oher4nyn', 3, 'PARAGRAPH', NULL, NULL, NULL, 'Для автора это важный этап, потому что статья уже видна, её уже можно найти и нередко уже можно цитировать по DOI и году онлайн-публикации.', 'Muallif uchun bu muhim bosqich, chunki maqola allaqachon ko‘rinadi, uni topish mumkin va ko‘pincha DOI hamda onlayn e’lon qilingan yil bo‘yicha iqtibos keltirish ham mumkin bo‘ladi.', 'For the author, this is an important stage because the article is already visible, searchable, and often citable by DOI and online publication year.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1b004dwrk11xu2d50b', 'cmrq0ao1a0048wrk1oher4nyn', 4, 'PARAGRAPH', 'Почему возникает путаница', 'Nega chalkashlik yuzaga keladi', 'Why confusion arises', 'Многие считают, что если статья уже опубликована на сайте, значит весь процесс завершён. На самом деле это часто только промежуточная, хотя и официальная публикационная стадия.', 'Ko‘pchilik maqola saytda e’lon qilingan bo‘lsa, demak butun jarayon tugadi deb o‘ylaydi. Aslida esa bu ko‘pincha faqat oraliq, garchi rasmiy nashr bosqichi bo‘lsa ham.', 'Many people assume that if the article is already published on the website, the whole process is complete. In reality, this is often only an intermediate, though official, publication stage.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1b004ewrk1y0zlkmx9', 'cmrq0ao1a0048wrk1oher4nyn', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Предварительная онлайн-публикация означает, что статья уже стала публичной, но её окончательное место в выпуске может быть назначено позже.', 'Dastlabki onlayn nashr maqola allaqachon ommaga ochilganini anglatadi, ammo uning sondagi yakuniy o‘rni keyinroq belgilanishi mumkin.', 'Preliminary online publication means that the article has already become public, but its final place in an issue may be assigned later.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1i004gwrk19jtelkzo', 'cmrq0ao1h004fwrk1mqaq7g06', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Один из частых вопросов авторов: если статья уже опубликована на сайте журнала, значит ли это, что номер уже вышел? Не обязательно.', 'Mualliflarning tez-tez beradigan savollaridan biri: agar maqola jurnal saytida allaqachon e’lon qilingan bo‘lsa, bu son ham chiqqanini anglatadimi? Shart emas.', 'One of the frequent questions from authors is: if an article is already published on the journal website, does that mean the issue has already been released? Not necessarily.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1i004hwrk1wbbgeaoh', 'cmrq0ao1h004fwrk1mqaq7g06', 1, 'LIST', 'Во многих издательских моделях статья проходит несколько стадий', 'Ko‘plab nashriyot modellarida maqola bir necha bosqichdan o‘tadi', 'In many publishing models, an article goes through several stages', NULL, NULL, NULL, '{accepted;,"online first / article in press;","final version of record;","later issue assignment."}', '{accepted;,"online first / article in press;","final version of record;","later issue assignment."}', '{accepted;,"online first / article in press;","final version of record;","later issue assignment."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1i004iwrk1yckl1iga', 'cmrq0ao1h004fwrk1mqaq7g06', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Это означает, что статья может быть уже доступна читателям и даже цитироваться, но её окончательное место в томе, выпуске или сборнике будет назначено позже.', 'Bu shuni anglatadiki, maqola o‘quvchilar uchun allaqachon ochiq bo‘lishi va hatto iqtibos qilinishi mumkin, ammo uning tom, son yoki to‘plamdagi yakuniy o‘rni keyinroq belgilanadi.', 'This means that the article may already be available to readers and even be citable, but its final place in a volume, issue, or collection will be assigned later.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1i004jwrk1zieia1j5', 'cmrq0ao1h004fwrk1mqaq7g06', 3, 'LIST', 'Для автора это важно по нескольким причинам', 'Bu muallif uchun bir necha sababga ko‘ra muhim', 'This matters to the author for several reasons', NULL, NULL, NULL, '{"онлайн-версия может появиться за недели или месяцы до выхода номера;","печатная версия или полный выпуск могут выйти позднее;","наличие статьи на сайте ещё не означает, что опубликован весь комплект материалов номера."}', '{"onlayn versiya son chiqishidan haftalar yoki oylar oldin paydo bo‘lishi mumkin;","bosma versiya yoki to‘liq son keyinroq chiqishi mumkin;","maqolaning saytda borligi butun son materiallari e’lon qilinganini anglatmaydi."}', '{"the online version may appear weeks or months before the issue release;","the print version or full issue may come later;","the presence of the article on the website does not mean the full set of issue materials has been published."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1i004kwrk1q9rjedk9', 'cmrq0ao1h004fwrk1mqaq7g06', 4, 'PARAGRAPH', NULL, NULL, NULL, 'В современной научной публикации это нормальная практика. Журнал может сначала опубликовать готовую статью онлайн, а затем включить её в номер согласно своему графику.', 'Zamonaviy ilmiy nashr amaliyotida bu normal holat. Jurnal avval tayyor maqolani onlayn e’lon qilib, keyin o‘z jadvaliga muvofiq songa kiritishi mumkin.', 'In modern scholarly publishing this is normal practice. A journal may first publish a completed article online and then include it in an issue according to its schedule.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1i004lwrk181eml9is', 'cmrq0ao1h004fwrk1mqaq7g06', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Онлайн-публикация статьи и выход полного номера журнала — это разные этапы одного процесса.', 'Maqolaning onlayn nashri va jurnalning to‘liq soni chiqishi — bitta jarayonning turli bosqichlaridir.', 'Online publication of an article and release of the full journal issue are different stages of the same process.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1o004nwrk12lw0vpg4', 'cmrq0ao1n004mwrk1ly2dghhu', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Авторы часто смешивают два разных понятия: тип статьи по содержанию — например, research article, review, editorial; и версия статьи по стадии публикации — manuscript, proof, version of record и так далее.', 'Mualliflar ko‘pincha ikki xil tushunchani aralashtirib yuboradilar: mazmuniga ko‘ra maqola turi — masalan, research article, review, editorial; va nashr bosqichiga ko‘ra maqola versiyasi — manuscript, proof, version of record va hokazo.', 'Authors often mix up two different concepts: the content type of an article—for example, research article, review, editorial—and the publication-stage version of the article, such as manuscript, proof, or version of record.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1o004owrk11woite0v', 'cmrq0ao1n004mwrk1ly2dghhu', 1, 'PARAGRAPH', NULL, NULL, NULL, 'Если говорить именно о публикационных версиях, международная практика различает несколько основных стадий.', 'Agar aynan nashr versiyalari haqida gapiradigan bo‘lsak, xalqaro amaliyot bir nechta asosiy bosqichlarni ajratadi.', 'If we speak specifically about publication versions, international practice distinguishes several main stages.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1o004pwrk1inc22m61', 'cmrq0ao1n004mwrk1ly2dghhu', 2, 'LIST', 'Основные публикационные версии', 'Asosiy nashr versiyalari', 'Main publication versions', NULL, NULL, NULL, '{"Author’s Original — исходная авторская версия;","Submitted Manuscript Under Review — версия, отправленная в журнал и находящаяся на рассмотрении;","Accepted Manuscript — текст после научного принятия, но до финального издательского оформления;","Proof — версия после вёрстки и редакционно-издательской обработки, направленная на проверку;","Version of Record — окончательная официально опубликованная версия;","Corrected Version of Record — исправленная опубликованная версия;","Enhanced Version of Record — опубликованная версия с дополнительными цифровыми материалами или улучшениями."}', '{"Author’s Original — muallifning dastlabki versiyasi;","Submitted Manuscript Under Review — jurnalga yuborilgan va ko‘rib chiqilayotgan versiya;","Accepted Manuscript — ilmiy qabuldan keyingi, lekin yakuniy nashriyot rasmiylashtiruvidan oldingi matn;","Proof — maket va tahririy-nashriyot ishlovidan keyingi, tekshirish uchun yuborilgan versiya;","Version of Record — yakuniy rasmiy chop etilgan versiya;","Corrected Version of Record — tuzatilgan chop etilgan versiya;","Enhanced Version of Record — qo‘shimcha raqamli materiallar yoki yaxshilanishlar bilan chop etilgan versiya."}', '{"Author’s Original — the original author version;","Submitted Manuscript Under Review — the version submitted to the journal and under review;","Accepted Manuscript — the text after scholarly acceptance but before final publisher formatting;","Proof — the version after layout and editorial processing sent for checking;","Version of Record — the final officially published version;","Corrected Version of Record — the corrected published version;","Enhanced Version of Record — the published version with additional digital materials or enhancements."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1o004qwrk1rbpo4q4q', 'cmrq0ao1n004mwrk1ly2dghhu', 3, 'LIST', 'Понимание этих стадий важно, потому что', 'Bu bosqichlarni tushunish muhim, chunki', 'Understanding these stages is important because', NULL, NULL, NULL, '{"не каждая версия одинаково подходит для цитирования;","разные журналы по-разному разрешают распространять preprint, accepted manuscript и финальную публикацию;","для отчётности и академических процедур может иметь значение, о какой версии идёт речь."}', '{"har bir versiya iqtibos keltirish uchun bir xil darajada mos kelmaydi;","turli jurnallar preprint, accepted manuscript va yakuniy nashrni turlicha tarqatishga ruxsat beradi;","hisobot va akademik jarayonlar uchun qaysi versiya nazarda tutilayotgani muhim bo‘lishi mumkin."}', '{"not every version is equally suitable for citation;","different journals allow sharing of preprints, accepted manuscripts, and final publications in different ways;","for reporting and academic procedures, it may matter which version is being referred to."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1o004rwrk1a4rd79py', 'cmrq0ao1n004mwrk1ly2dghhu', 4, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Научная статья — это не всегда один неизменный файл. У неё могут быть разные версии, и каждая из них имеет свой статус.', 'Ilmiy maqola har doim ham bitta o‘zgarmas fayl emas. Uning turli versiyalari bo‘lishi mumkin va har birining o‘z maqomi bor.', 'A scientific article is not always one unchanging file. It may have different versions, and each has its own status.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1s004twrk1xxyytkqy', 'cmrq0ao1r004swrk1ba924a71', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'В Scopus каждая запись относится к определённому document type. Это помогает системе правильно каталогизировать материалы, строить аналитику и рассчитывать показатели.', 'Scopus’da har bir yozuv ma’lum bir document type’ga tegishli bo‘ladi. Bu tizimga materiallarni to‘g‘ri kataloglash, analitika tuzish va ko‘rsatkichlarni hisoblashga yordam beradi.', 'In Scopus, each record belongs to a specific document type. This helps the system catalogue materials correctly, build analytics, and calculate indicators.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1s004uwrk17rimbrs6', 'cmrq0ao1r004swrk1ba924a71', 1, 'LIST', 'Среди наиболее распространённых типов документов в Scopus', 'Scopus’dagi eng ko‘p uchraydigan hujjat turlari', 'Among the most common document types in Scopus', NULL, NULL, NULL, '{Article,Article-in-Press,Review,"Conference Paper",Editorial,Letter,Note,"Short Survey",Erratum,"Retracted Article",Book,"Book Chapter","Data Paper"}', '{Article,Article-in-Press,Review,"Conference Paper",Editorial,Letter,Note,"Short Survey",Erratum,"Retracted Article",Book,"Book Chapter","Data Paper"}', '{Article,Article-in-Press,Review,"Conference Paper",Editorial,Letter,Note,"Short Survey",Erratum,"Retracted Article",Book,"Book Chapter","Data Paper"}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1s004vwrk1pup39yh8', 'cmrq0ao1r004swrk1ba924a71', 2, 'LIST', 'Почему это важно', 'Bu nima uchun muhim', 'Why this matters', NULL, NULL, NULL, '{"не все типы документов одинаково воспринимаются в научной практике;","при анализе профиля автора или журнала тип публикации имеет значение;","статья и editorial — это не одно и то же даже при наличии DOI и индексации."}', '{"ilmiy amaliyotda barcha hujjat turlari bir xil qabul qilinmaydi;","muallif yoki jurnal profilini tahlil qilganda nashr turi muhim ahamiyatga ega;","hatto DOI va indeksatsiya mavjud bo‘lsa ham, article va editorial bir xil narsa emas."}', '{"not all document types are viewed the same way in scholarly practice;","when analyzing an author or journal profile, the publication type matters;","an article and an editorial are not the same thing even if both have DOI and indexing."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1s004wwrk1czc1cva1', 'cmrq0ao1r004swrk1ba924a71', 3, 'LIST', 'Например', 'Masalan', 'For example', NULL, NULL, NULL, '{"article и review чаще воспринимаются как полноценные научные публикации;","editorial — это редакционный материал;","erratum — исправление;","conference paper — материал конференции;","article-in-press — статья на стадии ранней онлайн-публикации."}', '{"article va review ko‘proq to‘laqonli ilmiy nashr sifatida qabul qilinadi;","editorial — bu tahririy material;","erratum — tuzatish;","conference paper — konferensiya materiali;","article-in-press — erta onlayn nashr bosqichidagi maqola."}', '{"article and review are more often treated as full scholarly publications;","editorial is an editorial text;","erratum is a correction;","conference paper is conference material;","article-in-press is a paper at the early online publication stage."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1s004xwrk167ug000d', 'cmrq0ao1r004swrk1ba924a71', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Иногда издатель называет материал одним образом, а Scopus классифицирует его немного иначе. Поэтому при оценке публикации полезно смотреть не только на наличие записи, но и на её тип.', 'Ba’zan nashriyot materialni bir usulda ataydi, Scopus esa uni biroz boshqacha tasniflaydi. Shuning uchun nashrni baholashda faqat yozuv borligiga emas, balki uning turiga ham qarash foydali.', 'Sometimes a publisher labels a material one way, while Scopus classifies it somewhat differently. Therefore, when evaluating a publication, it is useful to look not only at whether the record exists but also at its type.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1s004ywrk1puly3kf5', 'cmrq0ao1r004swrk1ba924a71', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Если публикация видна в Scopus, важно смотреть не только на факт индексации, но и на тип документа, под которым она учтена.', 'Agar nashr Scopus’da ko‘rinayotgan bo‘lsa, faqat indeksatsiya faktiga emas, balki u qaysi hujjat turi ostida hisobga olinganiga ham qarash muhim.', 'If a publication is visible in Scopus, it is important to look not only at the fact of indexing but also at the document type under which it is counted.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1x0050wrk19bwv7lly', 'cmrq0ao1x004zwrk1dx0z6bh9', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Одна из самых частых ошибок — считать, что если статья уже появилась на сайте журнала, значит она уже есть в Scopus. На практике между этими этапами есть разница.', 'Eng ko‘p uchraydigan xatolardan biri — agar maqola jurnal saytida allaqachon paydo bo‘lgan bo‘lsa, demak u Scopus’da ham bor deb o‘ylashdir. Amalda bu bosqichlar o‘rtasida farq bor.', 'One of the most common mistakes is to think that if an article has already appeared on the journal website, then it is already in Scopus. In practice, there is a difference between these stages.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1x0051wrk1pg7v5jcw', 'cmrq0ao1x004zwrk1dx0z6bh9', 1, 'PARAGRAPH', 'Публикация статьи', 'Maqolaning nashri', 'Publication of an article', 'Это то, что делает журнал или издатель: принимает статью, оформляет её, размещает онлайн, включает в выпуск или публикует как version of record.', 'Bu jurnal yoki nashriyot qiladigan ish: maqolani qabul qiladi, rasmiylashtiradi, onlayn joylashtiradi, songa kiritadi yoki version of record sifatida chop etadi.', 'This is what the journal or publisher does: accepts the article, formats it, places it online, assigns it to an issue, or publishes it as the version of record.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1x0052wrk1kc405rwq', 'cmrq0ao1x004zwrk1dx0z6bh9', 2, 'PARAGRAPH', 'Индексация статьи', 'Maqolaning indeksatsiyasi', 'Indexing of the article', 'Это следующий этап: издатель передаёт метаданные, запись обрабатывается в базе, статья становится видимой в поиске и аналитике Scopus.', 'Bu keyingi bosqichdir: nashriyot metadata’ni yuboradi, yozuv bazada qayta ishlanadi va maqola Scopus qidiruvi hamda analitikasida ko‘rinadigan bo‘ladi.', 'This is the next stage: the publisher transfers metadata, the record is processed in the database, and the article becomes visible in Scopus search and analytics.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1x0053wrk1o2hm5ohw', 'cmrq0ao1x004zwrk1dx0z6bh9', 3, 'LIST', 'Из-за этого может возникать задержка', 'Shu sababli kechikish yuz berishi mumkin', 'Because of this, delays may occur', NULL, NULL, NULL, '{"даже если статья уже опубликована, она может ещё не появиться в базе;","она может появиться позже;","она может быть в базе, но не прикрепиться к нужному профилю автора."}', '{"maqola allaqachon chop etilgan bo‘lsa ham, u hali bazada ko‘rinmasligi mumkin;","u keyinroq paydo bo‘lishi mumkin;","u bazada bo‘lishi, lekin kerakli muallif profiliga birikmasligi mumkin."}', '{"even if the article is already published, it may not yet appear in the database;","it may appear later;","it may be in the database but not attached to the correct author profile."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1x0054wrk11q9iud4f', 'cmrq0ao1x004zwrk1dx0z6bh9', 4, 'LIST', 'Задержка зависит от', 'Kechikish quyidagilarga bog‘liq', 'The delay depends on', NULL, NULL, NULL, '{"темпа работы издателя;","качества метаданных;","особенностей журнала;","внутреннего цикла обработки данных."}', '{"nashriyot ishining tezligiga;","metadata sifatiga;","jurnalning o‘ziga xos xususiyatlariga;","ma’lumotlarni ichki qayta ishlash sikliga."}', '{"the publisher’s workflow speed;","the quality of the metadata;","journal-specific features;","the internal data processing cycle."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao1x0055wrk1ko8s0m2t', 'cmrq0ao1x004zwrk1dx0z6bh9', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Публикация статьи — это действие журнала. Индексация в Scopus — это отдельный этап, который может произойти позже.', 'Maqolaning nashri — jurnalning harakati. Scopus’dagi indeksatsiya esa keyinroq sodir bo‘lishi mumkin bo‘lgan alohida bosqichdir.', 'Publication of an article is an action by the journal. Indexing in Scopus is a separate stage that may occur later.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao220057wrk1ue7aomau', 'cmrq0ao220056wrk15gnfsd5o', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Если автор хочет убедиться, что статья действительно появилась в Scopus, лучше не ограничиваться одним вариантом поиска.', 'Agar muallif maqola haqiqatan ham Scopus’da paydo bo‘lganiga ishonch hosil qilmoqchi bo‘lsa, qidiruvning faqat bitta usuli bilan cheklanmagan ma’qul.', 'If an author wants to make sure that an article has actually appeared in Scopus, it is better not to rely on only one search method.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao220058wrk10tiqlho1', 'cmrq0ao220056wrk15gnfsd5o', 1, 'LIST', 'Основные способы проверки', 'Tekshirishning asosiy usullari', 'Main ways to verify', NULL, NULL, NULL, '{"1. Проверка по DOI — это самый точный способ, если DOI уже присвоен и корректно зарегистрирован.","2. Проверка по точному названию — иногда DOI ещё не ищется или введён с ошибкой, но статья уже присутствует в базе по заголовку.","3. Проверка через профиль автора — в Scopus Author Details можно смотреть список публикаций, вкладку Documents, Citation Overview и общие данные профиля.","4. Проверка по журналу — можно посмотреть выпуск, раздел или сам журнал в базе и проверить, появилась ли там нужная запись."}', '{"1. DOI bo‘yicha tekshirish — agar DOI allaqachon berilgan va to‘g‘ri ro‘yxatdan o‘tgan bo‘lsa, bu eng aniq usuldir.","2. Aniq sarlavha bo‘yicha tekshirish — ba’zan DOI hali topilmaydi yoki noto‘g‘ri kiritiladi, ammo maqola sarlavha orqali bazada allaqachon mavjud bo‘ladi.","3. Muallif profili orqali tekshirish — Scopus Author Details’da nashrlar ro‘yxati, Documents bo‘limi, Citation Overview va umumiy profil ma’lumotlarini ko‘rish mumkin.","4. Jurnal bo‘yicha tekshirish — bazada son, bo‘lim yoki jurnalning o‘zini ko‘rib, kerakli yozuv paydo bo‘lganmi-yo‘qmi tekshirish mumkin."}', '{"1. DOI check — this is the most accurate method if the DOI has already been assigned and correctly registered.","2. Exact-title check — sometimes the DOI is not yet searchable or is entered incorrectly, but the article is already present in the database by title.","3. Check through the author profile — in Scopus Author Details one can review the publication list, the Documents tab, Citation Overview, and overall profile data.","4. Check through the journal — one can review the issue, section, or journal itself in the database to see whether the needed record has appeared there."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao220059wrk196j2dai2', 'cmrq0ao220056wrk15gnfsd5o', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Если статья не отображается в профиле автора, это не всегда означает, что её нет в Scopus. Возможны и другие причины.', 'Agar maqola muallif profilida ko‘rinmasa, bu har doim ham uning Scopus’da yo‘qligini anglatmaydi. Boshqa sabablar ham bo‘lishi mumkin.', 'If the article does not appear in the author profile, this does not always mean that it is absent from Scopus. There may be other reasons.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao22005awrk14t9l5nc0', 'cmrq0ao220056wrk15gnfsd5o', 3, 'LIST', 'Например', 'Masalan', 'For example', NULL, NULL, NULL, '{"профиль автора обновился не полностью;","статья попала в другой профиль;","произошло некорректное объединение профилей;","в метаданных были ошибки в имени, аффилиации или данных автора."}', '{"muallif profili to‘liq yangilanmagan bo‘lishi mumkin;","maqola boshqa profilga tushgan bo‘lishi mumkin;","profillar noto‘g‘ri birlashtirilgan bo‘lishi mumkin;","metadata’da ism, affiliasiya yoki muallif ma’lumotlarida xatolar bo‘lishi mumkin."}', '{"the author profile may not have been fully updated;","the article may have been assigned to another profile;","profiles may have been merged incorrectly;","there may have been errors in the metadata for the name, affiliation, or author details."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao22005bwrk1kafok5ff', 'cmrq0ao220056wrk15gnfsd5o', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Поэтому логично проверять по нескольким признакам сразу.', 'Shuning uchun bir vaqtning o‘zida bir nechta belgi bo‘yicha tekshirish mantiqan to‘g‘ri bo‘ladi.', 'Therefore, it is logical to verify using several indicators at once.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao22005cwrk18z3hmilk', 'cmrq0ao220056wrk15gnfsd5o', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Надёжная проверка индексации — это не один поиск, а сочетание DOI, названия статьи, авторского профиля и данных журнала.', 'Indeksatsiyani ishonchli tekshirish — bu bitta qidiruv emas, balki DOI, maqola nomi, muallif profili va jurnal ma’lumotlarini birgalikda ko‘rishdir.', 'Reliable verification of indexing is not a single search but a combination of DOI, article title, author profile, and journal data.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao27005ewrk1yu2ui5hr', 'cmrq0ao26005dwrk17l9ye0c9', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Хотя у разных журналов свои редакционные правила, общий путь рукописи обычно похож.', 'Turli jurnallarning tahririy qoidalari turlicha bo‘lsa-da, qo‘lyozmaning umumiy yo‘li odatda o‘xshash bo‘ladi.', 'Although different journals have their own editorial rules, the general path of a manuscript is usually similar.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao27005fwrk1na13hy33', 'cmrq0ao26005dwrk17l9ye0c9', 1, 'LIST', 'Основные этапы', 'Asosiy bosqichlar', 'Main stages', NULL, NULL, NULL, '{"1. Initial quality check — редакция проверяет комплектность файлов, формальные требования, базовое качество текста, соблюдение этических норм и пригодность статьи для журнала.","2. Editor assigned — статья передаётся редактору, который решает, стоит ли отправлять её дальше на научное рассмотрение.","3. Peer review — внешние эксперты оценивают новизну, методы, качество анализа, обоснованность выводов и значимость результатов.","4. Decision — автор может получить reject, revise, accept with revisions или accept.","5. Final acceptance — после необходимых исправлений статья получает окончательное принятие.","6. Производственный этап — copyediting, typesetting, proofreading, online publication и issue assignment."}', '{"1. Initial quality check — tahririyat fayllarning to‘liqligini, rasmiy talablarni, matnning dastlabki sifatini, etik me’yorlarga rioya qilinishini va maqolaning jurnalga mosligini tekshiradi.","2. Editor assigned — maqola muharrirga beriladi va u uni ilmiy ko‘rib chiqishga yuborish kerakmi-yo‘qmi hal qiladi.","3. Peer review — tashqi ekspertlar yangilik, metodlar, tahlil sifati, xulosalarning asoslanganligi va natijalarning ahamiyatini baholaydilar.","4. Decision — muallif reject, revise, accept with revisions yoki accept qarorlaridan birini olishi mumkin.","5. Final acceptance — kerakli tuzatishlardan keyin maqola yakuniy qabulni oladi.","6. Ishlab chiqarish bosqichi — copyediting, typesetting, proofreading, online publication va issue assignment."}', '{"1. Initial quality check — the editorial office checks completeness of files, formal requirements, basic text quality, compliance with ethics, and the article’s suitability for the journal.","2. Editor assigned — the article is assigned to an editor who decides whether it should be sent for scholarly review.","3. Peer review — external experts evaluate novelty, methods, quality of analysis, validity of conclusions, and significance of results.","4. Decision — the author may receive reject, revise, accept with revisions, or accept.","5. Final acceptance — after necessary corrections, the article receives final acceptance.","6. Production stage — copyediting, typesetting, proofreading, online publication, and issue assignment."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao27005gwrk1m489ctsc', 'cmrq0ao26005dwrk17l9ye0c9', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Именно здесь многие авторы ошибочно думают, что «всё уже завершено», хотя на деле статья может ещё не быть опубликованной в окончательном виде и не индексироваться в базе.', 'Aynan shu yerda ko‘plab mualliflar «hammasi tugadi» deb xato o‘ylaydilar, aslida esa maqola hali yakuniy ko‘rinishda chop etilmagan va bazada indekslanmagan bo‘lishi mumkin.', 'This is exactly where many authors mistakenly think that “everything is already finished,” whereas in reality the article may still not be published in final form and may not yet be indexed in the database.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao27005hwrk109nhotsn', 'cmrq0ao26005dwrk17l9ye0c9', 3, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Принятие статьи означает, что журнал согласился её публиковать, но после этого ещё идут техническая подготовка, онлайн-размещение и возможная задержка до индексации.', 'Maqolaning qabul qilinishi jurnal uni chop etishga rozi bo‘lganini anglatadi, biroq undan keyin ham texnik tayyorlash, onlayn joylashtirish va indeksatsiyagacha bo‘lgan ehtimoliy kechikish davom etadi.', 'Acceptance means that the journal has agreed to publish the article, but after that there are still technical preparation steps, online posting, and a possible delay before indexing.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2c005jwrk1qoptfudv', 'cmrq0ao2b005iwrk1ds97t2ds', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Срок появления статьи в Scopus может отличаться от журнала к журналу и от выпуска к выпуску. Даже у индексируемого источника новые статьи не всегда попадают в базу сразу.', 'Maqolaning Scopus’da paydo bo‘lish muddati jurnaldan jurnalga va sondan songa farq qilishi mumkin. Hatto indekslanadigan manbada ham yangi maqolalar har doim darhol bazaga tushmaydi.', 'The time it takes for an article to appear in Scopus can vary from journal to journal and from issue to issue. Even in an indexed source, new articles do not always enter the database immediately.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2c005kwrk16dhqslkt', 'cmrq0ao2b005iwrk1ds97t2ds', 1, 'LIST', 'На скорость влияют', 'Tezlikka ta’sir qiluvchi omillar', 'What affects the speed', NULL, NULL, NULL, '{"издательский цикл;","регулярность передачи метаданных;","полнота и корректность данных;","особенности публикационной модели;","технические процессы обработки в базе."}', '{"nashriyot sikli;","metadata yuborish muntazamligi;","ma’lumotlarning to‘liqligi va to‘g‘riligi;","nashr modelining xususiyatlari;","bazadagi texnik qayta ishlash jarayonlari."}', '{"the publisher’s cycle;","regularity of metadata transfer;","completeness and correctness of the data;","features of the publication model;","technical processing workflows in the database."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2c005lwrk1l1ydif35', 'cmrq0ao2b005iwrk1ds97t2ds', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Поэтому корректнее говорить не «Scopus индексирует за конкретное число дней», а «индексация зависит от публикационного и технического цикла».', 'Shuning uchun «Scopus falon kun ichida indekslaydi» deyishdan ko‘ra, «indeksatsiya nashr va texnik siklga bog‘liq» deyish to‘g‘riroq bo‘ladi.', 'Therefore, it is more accurate to say not “Scopus indexes within a specific number of days,” but rather “indexing depends on the publication and technical cycle.”', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2c005mwrk1b3fal7yy', 'cmrq0ao2b005iwrk1ds97t2ds', 3, 'PARAGRAPH', 'Миф про удаление через 5 лет', '5 yildan keyin o‘chirish haqidagi mif', 'The myth about removal after 5 years', 'Иногда авторам говорят, что публикация может «исчезнуть из Scopus через 5 лет». Официальные материалы это не подтверждают.', 'Ba’zan mualliflarga nashr «5 yildan keyin Scopus’dan yo‘qolishi mumkin» deb aytiladi. Rasmiy materiallar buni tasdiqlamaydi.', 'Sometimes authors are told that a publication may “disappear from Scopus after 5 years.” Official materials do not confirm this.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2c005nwrk162fpneqs', 'cmrq0ao2b005iwrk1ds97t2ds', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Scopus указывает, что если журнал затем перестаёт индексироваться, уже включённый контент обычно остаётся в базе как часть научной записи. Исключения возможны только в серьёзных случаях доказанной неэтичной публикационной практики.', 'Scopus shuni ko‘rsatadiki, agar jurnal keyinchalik indekslanmay qolsa ham, ilgari kiritilgan kontent odatda ilmiy yozuvning bir qismi sifatida bazada qoladi. Istisnolar faqat isbotlangan jiddiy noetik nashriyot amaliyoti holatlarida bo‘lishi mumkin.', 'Scopus indicates that if a journal later stops being indexed, the content already included usually remains in the database as part of the scholarly record. Exceptions are possible only in serious cases of proven unethical publication practice.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2c005owrk1x81uvkxl', 'cmrq0ao2b005iwrk1ds97t2ds', 5, 'PARAGRAPH', NULL, NULL, NULL, 'Цифра «5 лет» в документах Scopus относится к другому вопросу — к сроку повторного рассмотрения отдельных discontinued titles, а не к автоматическому удалению уже проиндексированных статей.', 'Scopus hujjatlaridagi «5 yil» raqami boshqa masalaga — ayrim discontinued titles’ni qayta ko‘rib chiqish muddatiga tegishli, allaqachon indekslangan maqolalarni avtomatik o‘chirishga emas.', 'The figure “5 years” in Scopus documents refers to another issue—the time frame for reconsidering certain discontinued titles, not the automatic deletion of already indexed articles.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2c005pwrk1rhv24ag1', 'cmrq0ao2b005iwrk1ds97t2ds', 6, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Задержка индексации — это нормальная ситуация. А утверждение про автоматическое удаление статьи из Scopus через 5 лет не подтверждается официальной политикой базы.', 'Indeksatsiyadagi kechikish — normal holat. Ammo maqola Scopus’dan 5 yildan keyin avtomatik o‘chiriladi degan gap bazaning rasmiy siyosati bilan tasdiqlanmaydi.', 'A delay in indexing is normal. But the claim that an article is automatically removed from Scopus after 5 years is not supported by the database’s official policy.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2g005rwrk1hmyzuu2l', 'cmrq0ao2g005qwrk1749quff4', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Научная статья — один из основных способов представить исследовательский результат научному сообществу. Её задача — не просто изложить мнение, а зафиксировать работу так, чтобы другие специалисты могли понять, что именно делал автор, оценить качество исследования, использовать результаты в дальнейшей работе, проверить выводы и сопоставить их с другими данными.', 'Ilmiy maqola ilmiy natijani ilmiy hamjamiyatga taqdim etishning asosiy usullaridan biridir. Uning vazifasi shunchaki fikr bildirish emas, balki ishni shunday qayd etishki, boshqa mutaxassislar muallif aynan nima qilganini tushunsin, tadqiqot sifatini baholasin, natijalardan keyingi ishlarida foydalansin, xulosalarni tekshirsin va ularni boshqa ma’lumotlar bilan solishtirsin.', 'A scientific article is one of the main ways to present a research result to the scholarly community. Its task is not merely to express an opinion, but to record the work in such a way that other specialists can understand what the author actually did, assess the quality of the research, use the results in further work, verify the conclusions, and compare them with other data.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2g005swrk143wcu3nh', 'cmrq0ao2g005qwrk1749quff4', 1, 'LIST', 'Обычно научная статья включает', 'Odatda ilmiy maqola quyidagilarni o‘z ichiga oladi', 'A scientific article usually includes', NULL, NULL, NULL, '{заголовок;,аннотацию;,введение;,методы;,результаты;,обсуждение;,выводы;,"список литературы."}', '{sarlavha;,annotatsiya;,kirish;,metodlar;,natijalar;,muhokama;,xulosalar;,"adabiyotlar ro‘yxati."}', '{title;,abstract;,introduction;,methods;,results;,discussion;,conclusions;,references.}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2g005twrk1zy8ug5i9', 'cmrq0ao2g005qwrk1749quff4', 2, 'PARAGRAPH', NULL, NULL, NULL, 'В разговорной речи часто смешивают термины scientific paper, research article, manuscript, journal article. Но между ними есть нюансы. Например, manuscript — это чаще рукопись до публикации или на стадии подачи, а journal article — уже публикационный формат статьи.', 'Og‘zaki nutqda scientific paper, research article, manuscript, journal article atamalari ko‘pincha aralashtirib yuboriladi. Ammo ular o‘rtasida nozik farqlar bor. Masalan, manuscript odatda nashrgacha bo‘lgan yoki topshirish bosqichidagi qo‘lyozmani bildiradi, journal article esa allaqachon nashr formatidagi maqolani anglatadi.', 'In everyday usage, terms such as scientific paper, research article, manuscript, and journal article are often mixed up. However, there are nuances between them. For example, a manuscript is usually a text before publication or at the submission stage, whereas a journal article is the publication format of the paper.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2g005uwrk187syuekq', 'cmrq0ao2g005qwrk1749quff4', 3, 'LIST', 'Научной статью делает исследовательская логика', 'Ilmiy maqolani ilmiy qiladigan narsa — tadqiqot mantig‘i', 'What makes an article scientific is research logic', NULL, NULL, NULL, '{"есть вопрос или задача;","есть метод;","есть данные или аргументы;","есть выводы;","есть связь с научной литературой."}', '{"savol yoki vazifa mavjud bo‘ladi;","metod mavjud bo‘ladi;","ma’lumotlar yoki dalillar mavjud bo‘ladi;","xulosalar mavjud bo‘ladi;","ilmiy adabiyot bilan bog‘liqlik mavjud bo‘ladi."}', '{"there is a question or problem;","there is a method;","there are data or arguments;","there are conclusions;","there is a connection with the scholarly literature."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2g005vwrk16c045xik', 'cmrq0ao2g005qwrk1749quff4', 4, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Научная статья — это не просто текст по теме, а оформленное исследовательское сообщение, рассчитанное на профессиональную оценку и использование.', 'Ilmiy maqola — bu shunchaki mavzu bo‘yicha matn emas, balki professional baholash va foydalanishga mo‘ljallangan rasmiylashtirilgan tadqiqot xabaridir.', 'A scientific article is not just a text on a topic, but a formatted research communication intended for professional evaluation and use.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2m005xwrk13h5q4hnn', 'cmrq0ao2l005wwrk1q3x9atji', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Многие авторы воспринимают публикацию как момент загрузки файла в редакционную систему. На самом деле публикация — это более длинный и формальный процесс.', 'Ko‘plab mualliflar nashrni faylni tahririy tizimga yuklash payti deb qabul qiladilar. Aslida nashr bundan ancha uzun va rasmiy jarayondir.', 'Many authors perceive publication as the moment of uploading a file into the editorial system. In reality, publication is a longer and more formal process.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao39006ywrk1lwlfzsfb', 'cmrq0ao39006uwrk119hwt0ue', 3, 'PARAGRAPH', 'На что смотреть в первую очередь', 'Avvalo nimaga qarash kerak', 'What to look at first', 'Главный ориентир — текущий издатель и его официально указанный адрес. Именно эти данные лучше всего показывают, к какой стране относится журнал в издательском и библиографическом смысле.', 'Asosiy mezon — amaldagi nashriyot va uning rasmiy ko‘rsatilgan manzili. Aynan shu ma’lumotlar jurnal nashriyot va bibliografik ma’noda qaysi mamlakatga tegishli ekanini eng yaxshi ko‘rsatadi.', 'The main reference point is the current publisher and its officially stated address. These data best show which country the journal belongs to in a publishing and bibliographic sense.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2m005ywrk1fcgqrf6z', 'cmrq0ao2l005wwrk1q3x9atji', 1, 'LIST', 'Обычно он включает', 'Odatda u quyidagilarni o‘z ichiga oladi', 'It usually includes', NULL, NULL, NULL, '{"подготовку рукописи;","подачу в журнал;","редакционный отбор;","peer review;",правки;,"принятие статьи;","proofing и издательскую подготовку;",онлайн-публикацию;,"включение в выпуск или публикацию как final version."}', '{"qo‘lyozmani tayyorlash;","jurnalga topshirish;","tahririy saralash;","peer review;",tuzatishlar;,"maqolaning qabul qilinishi;","proofing va nashriyot tayyorlovini;","onlayn nashrni;","songa kiritish yoki final version sifatida chop etishni."}', '{"preparation of the manuscript;","submission to the journal;","editorial screening;","peer review;",revisions;,"acceptance of the article;","proofing and publisher preparation;","online publication;","assignment to an issue or publication as the final version."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2m005zwrk16drs2ij8', 'cmrq0ao2l005wwrk1q3x9atji', 2, 'PARAGRAPH', NULL, NULL, NULL, 'Публикация означает, что статья становится частью официальной научной записи журнала. В зависимости от политики издателя это может происходить при online first, при article in press, при выходе финального выпуска или при публикации version of record.', 'Nashr maqolaning jurnalning rasmiy ilmiy yozuvining bir qismiga aylanishini anglatadi. Nashriyot siyosatiga qarab bu online first, article in press, yakuniy son chiqishi yoki version of record chop etilishi vaqtida sodir bo‘lishi mumkin.', 'Publication means that the article becomes part of the journal’s official scholarly record. Depending on publisher policy, this may occur at the online first stage, as article in press, upon final issue release, or at the publication of the version of record.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2m0060wrk15ulgx967', 'cmrq0ao2l005wwrk1q3x9atji', 3, 'LIST', 'Важно не путать разные состояния', 'Turli holatlarni aralashtirmaslik kerak', 'It is important not to confuse different statuses', NULL, NULL, NULL, '{"текст написан;","статья отправлена;","статья принята;","статья опубликована;","статья проиндексирована."}', '{"matn yozilgan;","maqola yuborilgan;","maqola qabul qilingan;","maqola chop etilgan;","maqola indekslangan."}', '{"the text is written;","the article is submitted;","the article is accepted;","the article is published;","the article is indexed."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2m0061wrk17j1ox5vh', 'cmrq0ao2l005wwrk1q3x9atji', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Все эти статусы разные, и для автора это имеет практическое значение.', 'Bu maqomlarning barchasi bir-biridan farq qiladi va muallif uchun bu amaliy ahamiyatga ega.', 'All of these statuses are different, and this distinction has practical significance for the author.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2m0062wrk1p3w24huw', 'cmrq0ao2l005wwrk1q3x9atji', 5, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Публикация в журнале — это не просто отправка статьи, а официальное включение работы в публикационную систему журнала.', 'Jurnalda nashr — bu shunchaki maqolani yuborish emas, balki ishning jurnalning nashr tizimiga rasmiy kiritilishidir.', 'Publication in a journal is not merely submission of an article, but the official inclusion of the work into the journal’s publication system.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2s0064wrk1tukjla8o', 'cmrq0ao2s0063wrk1g755l3w4', 0, 'PARAGRAPH', 'Подробно', 'Batafsil', 'In detail', 'Научный журнал — это не просто сайт со статьями и не любое издание с международным названием. Это публикационная площадка, которая работает как часть научной коммуникации.', 'Ilmiy jurnal shunchaki maqolalar joylangan sayt ham emas, xalqaro nomga ega istalgan nashr ham emas. Bu ilmiy kommunikatsiyaning bir qismi sifatida ishlaydigan nashr maydonidir.', 'A scientific journal is not just a website with articles and not any publication with an international-sounding title. It is a publishing venue that functions as part of scholarly communication.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2s0065wrk14pf7hzua', 'cmrq0ao2s0063wrk1g755l3w4', 1, 'LIST', 'Обычно у научного журнала есть', 'Odatda ilmiy jurnalda quyidagilar bo‘ladi', 'A scientific journal usually has', NULL, NULL, NULL, '{"постоянное название;",ISSN;,издатель;,"редакционная коллегия;","правила для авторов;","архив выпусков;","система рассмотрения рукописей;","публикационная и этическая политика."}', '{"doimiy nom;",ISSN;,nashriyot;,"tahrir hay’ati;","mualliflar uchun qoidalar;","sonlar arxivi;","qo‘lyozmalarni ko‘rib chiqish tizimi;","nashr va etika siyosati."}', '{"a stable title;","an ISSN;","a publisher;","an editorial board;","author guidelines;","an archive of issues;","a manuscript review system;","publication and ethics policies."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2s0066wrk19fx0cg0g', 'cmrq0ao2s0063wrk1g755l3w4', 2, 'LIST', 'Научный журнал может публиковать', 'Ilmiy jurnal quyidagilarni chop etishi mumkin', 'A scientific journal may publish', NULL, NULL, NULL, '{"original research articles;","review articles;","short communications;","case studies;","methods papers;",editorials;,letters.}', '{"original research articles;","review articles;","short communications;","case studies;","methods papers;",editorials;,letters.}', '{"original research articles;","review articles;","short communications;","case studies;","methods papers;",editorials;,letters.}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao2s0067wrk1xyrywssw', 'cmrq0ao2s0063wrk1g755l3w4', 3, 'LIST', 'От обычного информационного сайта его отличают', 'Uni oddiy axborot saytidan ajratib turadigan belgilar', 'What distinguishes it from an ordinary information site', NULL, NULL, NULL, '{"серийность выпуска;","формализованная редакционная процедура;","наличие метаданных;","сохранение архива;","ориентация на научную, а не развлекательную или рекламную функцию."}', '{"davriy chiqishi;","rasmiylashtirilgan tahririy jarayon;","metadata mavjudligi;","arxivning saqlanishi;","ko‘ngilochar yoki reklama emas, ilmiy vazifaga yo‘naltirilganligi."}', '{"serial/periodic publication;","a formalized editorial procedure;","the presence of metadata;","preservation of an archive;","orientation toward a scholarly rather than entertainment or promotional function."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao39006zwrk1gx7xbioq', 'cmrq0ao39006uwrk119hwt0ue', 4, 'LIST', 'Проверять это лучше последовательно', 'Buni izchil tekshirgan ma’qul', 'It is best checked step by step', NULL, NULL, NULL, '{"1. Сайт журнала: кто указан как publisher, какой дан официальный адрес, что написано в разделе About Journal, где находится editorial office, есть ли publishing information или imprint.","2. ISSN Portal и библиографические записи: там могут быть указаны название издания, издатель, место публикации и версия ресурса.","3. Scopus Source Details: если журнал индексируется в Scopus, стоит посмотреть и его карточку в базе.","4. Дополнительные метаданные: иногда полезно смотреть регистрационные сведения в Crossref или других каталогах."}', '{"1. Jurnal sayti: publisher sifatida kim ko‘rsatilgan, rasmiy manzil qanday, About Journal bo‘limida nima yozilgan, editorial office qayerda, publishing information yoki imprint bormi.","2. ISSN Portal va bibliografik yozuvlar: u yerda nashr nomi, nashriyot, chop etilish joyi va resurs versiyasi ko‘rsatilgan bo‘lishi mumkin.","3. Scopus Source Details: agar jurnal Scopus’da indekslansa, uning bazadagi kartasini ham ko‘rish kerak.","4. Qo‘shimcha metadata: ba’zan Crossref yoki boshqa kataloglardagi ro‘yxatga olish ma’lumotlarini ko‘rish foydali."}', '{"1. The journal website: who is listed as publisher, what official address is given, what is written in About Journal, where the editorial office is located, and whether publishing information or an imprint is provided.","2. ISSN Portal and bibliographic records: these may show the publication title, publisher, place of publication, and resource version.","3. Scopus Source Details: if the journal is indexed in Scopus, its source card in the database should also be reviewed.","4. Additional metadata: sometimes it is useful to check registration details in Crossref or other catalogues."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao390070wrk1kslivfo7', 'cmrq0ao39006uwrk119hwt0ue', 5, 'LIST', 'Что не стоит использовать как основной критерий', 'Asosiy mezon sifatida nimadan foydalanmaslik kerak', 'What should not be used as the main criterion', NULL, NULL, NULL, '{"доменную зону;","язык интерфейса;","гражданство редактора;","формулировку «international journal»;","номер ISSN."}', '{"domen zonasini;","interfeys tilini;","muharrirning fuqaroligini;","«international journal» degan ifodani;","ISSN raqamini."}', '{"the domain zone;","the interface language;","the editor’s citizenship;","the phrase “international journal”;","the ISSN number."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao390071wrk1nmnndit5', 'cmrq0ao39006uwrk119hwt0ue', 6, 'PARAGRAPH', NULL, NULL, NULL, 'ISSN, например, не кодирует страну. По самому номеру нельзя узнать, где издаётся журнал.', 'Masalan, ISSN mamlakatni kodlamaydi. Faqat raqamning o‘zidan jurnal qayerda nashr etilishini bilib bo‘lmaydi.', 'For example, ISSN does not encode a country. You cannot tell where a journal is published from the number alone.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao390072wrk1jszefuen', 'cmrq0ao39006uwrk119hwt0ue', 7, 'LIST', 'Почему это важно', 'Bu nega muhim', 'Why this matters', NULL, NULL, NULL, '{"при выборе площадки для публикации;","при отчётности;","при оценке репутации издателя;","при проверке достоверности информации о журнале."}', '{"nashr maydonini tanlashda;",hisobotda;,"nashriyot obro‘sini baholashda;","jurnal haqidagi ma’lumotlarning ishonchliligini tekshirishda."}', '{"when choosing a publication venue;","in reporting;","when assessing the publisher’s reputation;","when verifying the reliability of information about the journal."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao390073wrk1xyhpevkt', 'cmrq0ao39006uwrk119hwt0ue', 8, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'Страну журнала определяют прежде всего по издателю и официальной библиографической записи, а не по внешнему виду сайта и не по названию.', 'Jurnal mamlakati, avvalo, sayt ko‘rinishi yoki nomiga qarab emas, balki nashriyot va rasmiy bibliografik yozuv asosida aniqlanadi.', 'A journal’s country is determined primarily by the publisher and the official bibliographic record, not by the look of the website or the journal’s title.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g0075wrk1d3npjigx', 'cmrq0ao3g0074wrk13y390m3e', 0, 'PARAGRAPH', 'Зачем нужен IMRAD', 'IMRAD nima uchun kerak', 'Why IMRAD is needed', 'Эта структура помогает излагать исследование последовательно и понятно. Читатель сразу видит: зачем проводилась работа, как она выполнялась, что получилось и как автор объясняет результаты.', 'Bu tuzilma tadqiqotni izchil va tushunarli bayon qilishga yordam beradi. O‘quvchi darhol quyidagilarni ko‘radi: ish nima uchun o‘tkazilgan, u qanday bajarilgan, nima natija olingan va muallif natijalarni qanday tushuntiradi.', 'This structure helps present research in a consistent and understandable way. The reader immediately sees why the work was conducted, how it was performed, what was obtained, and how the author explains the results.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g0076wrk1rpep6nch', 'cmrq0ao3g0074wrk13y390m3e', 1, 'LIST', 'Поэтому IMRAD удобен', 'Shuning uchun IMRAD qulay', 'Therefore IMRAD is convenient', NULL, NULL, NULL, '{"для автора — как каркас текста;","для рецензента — как понятная схема оценки;","для читателя — как логичный путь через статью."}', '{"muallif uchun — matn karkasi sifatida;","taqrizchi uchun — baholashning tushunarli sxemasi sifatida;","o‘quvchi uchun — maqola bo‘ylab mantiqiy yo‘l sifatida."}', '{"for the author — as a text framework;","for the reviewer — as a clear evaluation scheme;","for the reader — as a logical path through the article."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g0077wrk1mdr48w2i', 'cmrq0ao3g0074wrk13y390m3e', 2, 'PARAGRAPH', 'Как устроен IMRAD', 'IMRAD qanday tuzilgan', 'How IMRAD is structured', 'Introduction — Введение. Во введении автор показывает, какую проблему он рассматривает, почему тема важна и какова цель исследования. Здесь формулируется вопрос, задача или гипотеза.', 'Introduction — Kirish. Kirishda muallif qanday muammoni ko‘rib chiqayotganini, mavzu nega muhimligini va tadqiqot maqsadi nimadan iboratligini ko‘rsatadi. Shu yerda savol, vazifa yoki gipoteza shakllantiriladi.', 'Introduction — In the introduction, the author shows what problem is being considered, why the topic is important, and what the aim of the research is. The question, task, or hypothesis is formulated here.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g0078wrk14ug6ge3i', 'cmrq0ao3g0074wrk13y390m3e', 3, 'PARAGRAPH', NULL, NULL, NULL, 'Methods — Методы. В этом разделе объясняется, как именно проводилось исследование: какие материалы использовались, какие процедуры применялись, как собирались данные, как выполнялся анализ. Именно этот раздел показывает, насколько исследование прозрачно и воспроизводимо.', 'Methods — Metodlar. Bu bo‘limda tadqiqot aynan qanday o‘tkazilgani tushuntiriladi: qanday materiallardan foydalanilgani, qanday protseduralar qo‘llangani, ma’lumotlar qanday yig‘ilgani va tahlil qanday bajarilgani. Aynan shu bo‘lim tadqiqot qanchalik shaffof va takrorlanuvchi ekanini ko‘rsatadi.', 'Methods — This section explains exactly how the study was conducted: what materials were used, what procedures were applied, how data were collected, and how analysis was performed. This section shows how transparent and reproducible the research is.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g0079wrk18k210emj', 'cmrq0ao3g0074wrk13y390m3e', 4, 'PARAGRAPH', NULL, NULL, NULL, 'Results — Результаты. Здесь приводятся фактические результаты исследования: численные данные, наблюдения, таблицы, графики, выявленные связи и различия. Это раздел о том, что получилось, а не о том, как это оценивать.', 'Results — Natijalar. Bu yerda tadqiqotning faktik natijalari keltiriladi: sonli ma’lumotlar, kuzatishlar, jadvallar, grafiklar, aniqlangan bog‘lanishlar va farqlar. Bu bo‘lim nima olingani haqida, uni qanday baholash haqida emas.', 'Results — Here the factual findings of the research are presented: numerical data, observations, tables, graphs, identified relationships, and differences. This section is about what was obtained, not how to interpret it.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g007awrk18h4v2o7t', 'cmrq0ao3g0074wrk13y390m3e', 5, 'PARAGRAPH', NULL, NULL, NULL, 'Discussion — Обсуждение. В обсуждении автор объясняет смысл полученных результатов: что они означают, насколько они важны, как соотносятся с другими работами, какие есть ограничения и какие выводы можно сделать. Именно здесь результаты превращаются в научное объяснение.', 'Discussion — Muhokama. Muhokamada muallif olingan natijalarning ma’nosini tushuntiradi: ular nimani anglatadi, qanchalik muhim, boshqa ishlar bilan qanday bog‘lanadi, qanday cheklovlar bor va qanday xulosalar chiqarish mumkin. Aynan shu yerda natijalar ilmiy izohga aylanadi.', 'Discussion — In the discussion, the author explains the meaning of the obtained results: what they mean, how important they are, how they relate to other works, what limitations exist, and what conclusions can be drawn. This is where results turn into scientific explanation.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g007bwrk10xu83tb4', 'cmrq0ao3g0074wrk13y390m3e', 6, 'LIST', 'Почему эта структура считается стандартной', 'Nega bu tuzilma standart hisoblanadi', 'Why this structure is considered standard', NULL, NULL, NULL, '{"она делает статью логичной;",читаемой;,"удобной для рецензирования;","понятной для повторной проверки;","пригодной для научной коммуникации."}', '{"u maqolani mantiqiy qiladi;","o‘qishga qulay qiladi;","taqriz qilish uchun qulay qiladi;","qayta tekshirish uchun tushunarli qiladi;","ilmiy kommunikatsiya uchun yaroqli qiladi."}', '{"it makes the article logical;",readable;,"convenient for peer review;","clear for re-checking;","suitable for scholarly communication."}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g007cwrk1jgnyawir', 'cmrq0ao3g0074wrk13y390m3e', 7, 'PARAGRAPH', NULL, NULL, NULL, 'Он особенно характерен для оригинальных исследовательских статей. При этом не все жанры обязаны строго ему следовать. Например, обзоры, case reports, editorials и некоторые другие типы материалов могут строиться иначе.', 'U ayniqsa original tadqiqot maqolalari uchun xosdir. Biroq barcha janrlar unga qat’iy rioya qilishi shart emas. Masalan, sharhlar, case reportlar, editorials va ayrim boshqa material turlari boshqacha tuzilishi mumkin.', 'It is especially characteristic of original research articles. At the same time, not all genres must follow it strictly. For example, reviews, case reports, editorials, and some other types of materials may be structured differently.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g007dwrk1d8ug5hd6', 'cmrq0ao3g0074wrk13y390m3e', 8, 'PARAGRAPH', 'Когда IMRAD особенно важен', 'IMRAD qachon ayniqsa muhim', 'When IMRAD is especially important', 'IMRAD особенно полезен там, где статья описывает собственное исследование автора. В таком тексте важно не только сообщить вывод, но и показать путь, по которому к нему пришли.', 'IMRAD ayniqsa maqola muallifning o‘z tadqiqotini tasvirlagan joyda foydalidir. Bunday matnda nafaqat xulosani bildirish, balki unga qanday yo‘l bilan kelinganini ham ko‘rsatish muhim.', 'IMRAD is especially useful where the article describes the author’s own research. In such a text, it is important not only to report the conclusion, but also to show the path by which it was reached.', '{}', '{}', '{}');
INSERT INTO public."UsefulBlock" (id, "pageId", "sortOrder", type, "titleRu", "titleUz", "titleEn", "textRu", "textUz", "textEn", "itemsRu", "itemsUz", "itemsEn") VALUES ('cmrq0ao3g007ewrk1njbydq5b', 'cmrq0ao3g0074wrk13y390m3e', 9, 'PARAGRAPH', 'Что важно запомнить', 'Eslab qolish muhim', 'What is important to remember', 'IMRAD — это не просто формальность, а удобная и устойчивая логика научной статьи: сначала проблема, потом методы, затем результаты и их объяснение.', 'IMRAD — bu shunchaki rasmiylik emas, balki ilmiy maqolaning qulay va barqaror mantig‘idir: avval muammo, keyin metodlar, so‘ng natijalar va ularning izohi.', 'IMRAD is not just a formality, but a convenient and stable logic of a scientific article: first the problem, then methods, then results and their explanation.', '{}', '{}', '{}');
